const CharacterSummary: React.FC<{ character: Character }> = ({ character: oCharacter }) => {
    const { t: fnT } = useI18n();

    // Validation Logic
    const aChecks = useMemo(() => {
        const aList = [];

        // Concept
        const bConceptValid = !!(oCharacter.name && oCharacter.concept && oCharacter.ambition && oCharacter.desire);
        aList.push({ label: fnT('steps.concept'), isValid: bConceptValid, error: fnT('summary.missing_concept') });

        // Clan
        const bClanValid = !!oCharacter.clan;
        aList.push({ label: fnT('steps.clan'), isValid: bClanValid, error: fnT('summary.missing_clan') });

        // Attributes
        const nAttrSum = (Object.values(oCharacter.attributes) as number[]).reduce((nAcc: number, nVal: number) => nAcc + nVal, 0);
        // V5 spread: 4+3+3+3+2+2+2+2+1 = 22
        const bAttributesValid = nAttrSum === 22;
        aList.push({ label: fnT('steps.attributes'), isValid: bAttributesValid, error: fnT('summary.error_attributes') });

        // Skills
        const nSkillSum = (Object.values(oCharacter.skills) as number[]).reduce((nAcc: number, nVal: number) => nAcc + nVal, 0);
        // Min check for any spread (Specialist: 4+9+6+3 = 22)
        const bSkillsValid = nSkillSum >= 22; 
        aList.push({ label: fnT('steps.skills'), isValid: bSkillsValid, error: fnT('summary.error_skills') });

        // Predator Type
        const bPredatorValid = !!oCharacter.predatorType;
        aList.push({ label: fnT('finishingTouches.predatorType.title'), isValid: bPredatorValid, error: fnT('summary.missing_predator') });

        // Finishing Touches (Disciplines + Advantages + Flaws)
        const nDisciplineDots = (Object.values(oCharacter.disciplines) as number[]).reduce((nAcc: number, nVal: number) => nAcc + nVal, 0);
        const bDisciplinesValid = nDisciplineDots >= 3;

        // Note: oCharacter includes predator type advantages. The summary might need to be smart about 7/2 rule vs total.
        // For simplicity, we check totals. A standard char should have roughly 7 (base) + predator advs.
        // But users might add more with XP. Let's just check they have *at least* the minimums.
        const nAdvSum = oCharacter.advantages.reduce((nAcc, oVal) => nAcc + oVal.cost, 0);
        const nFlawSum = oCharacter.flaws.reduce((nAcc, oVal) => nAcc + oVal.cost, 0);
        const bAdvantagesValid = nAdvSum >= 7;
        const bFlawsValid = nFlawSum >= 2;

        const bFinishingValid = bDisciplinesValid && bAdvantagesValid && bFlawsValid;
        let sFinishingError = '';
        if (!bDisciplinesValid) sFinishingError = fnT('summary.error_disciplines');
        else if (!bAdvantagesValid) sFinishingError = fnT('summary.error_advantages');
        else if (!bFlawsValid) sFinishingError = fnT('summary.error_flaws');

        aList.push({ label: fnT('steps.finishingTouches'), isValid: bFinishingValid, error: sFinishingError });

        return aList;
    }, [oCharacter, fnT]);

    const bAllValid = aChecks.every(c => c.isValid);

    return (
        <GothicFrame className="text-left">
             <div className="p-6 bg-gray-800/50">
                <div className="flex items-center mb-6">
                    {bAllValid ? <CheckCircle /> : <ExclamationCircle />}
                    <div className="ml-3">
                        <h3 className="text-xl font-bold text-gray-200">{fnT('summary.title')}</h3>
                        <p className="text-gray-400 text-sm">{bAllValid ? fnT('summary.readySubtitle') : fnT('summary.incompleteSubtitle')}</p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {aChecks.map((oCheck, nIdx) => (
                        <div key={nIdx} className={`flex items-center p-3 rounded-lg border ${oCheck.isValid ? 'bg-green-900 bg-opacity-20 border-green-900' : 'bg-red-900 bg-opacity-20 border-red-900'}`}>
                            <div className="flex-shrink-0 mr-3">
                                {oCheck.isValid ? (
                                    <svg className="w-6 h-6 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                    </svg>
                                ) : (
                                    <svg className="w-6 h-6 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                    </svg>
                                )}
                            </div>
                            <div>
                                <h4 className={`font-bold ${oCheck.isValid ? 'text-green-400' : 'text-red-400'}`}>{oCheck.label}</h4>
                                {!oCheck.isValid && <p className="text-xs text-red-300 mt-1">{oCheck.error}</p>}
                            </div>
                        </div>
                    ))}
                </div>
             </div>
        </GothicFrame>
    );
};

// --- STORAGE MANAGER COMPONENT --- //
interface StorageModalProps {
    mode: 'save' | 'load';
    onClose: () => void;
    currentName?: string;
    onSave: (name: string) => void;
    onLoad: (name: string) => void;
    onDelete: (name: string) => void;
}

const StorageModal: React.FC<StorageModalProps> = ({ mode: sMode, onClose: fnOnClose, currentName: sCurrentName, onSave: fnOnSave, onLoad: fnOnLoad, onDelete: fnOnDelete }) => {
    const { t: fnT } = useI18n();
    const [sNameInput, fnSetNameInput] = useState(sCurrentName || '');
    const [aSavedFiles, fnSetSavedFiles] = useState<string[]>([]);

    // Fetch saved files
    useEffect(() => {
        if (typeof window !== 'undefined') {
            const aKeys = [];
            for (let nI = 0; nI < localStorage.length; nI++) {
                const sKey = localStorage.key(nI);
                if (sKey && sKey.startsWith('vtm_save_')) {
                    aKeys.push(sKey.replace('vtm_save_', ''));
                }
            }
            fnSetSavedFiles(aKeys.sort());
        }
    }, []);

    const fnHandleSave = () => {
        if (!sNameInput.trim()) return;
        if (aSavedFiles.includes(sNameInput) && !window.confirm(fnT('storage.overwriteWarning'))) {
            return;
        }
        fnOnSave(sNameInput);
        fnOnClose();
    };

    const fnHandleDelete = (sName: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (window.confirm(fnT('storage.deleteConfirm'))) {
            fnOnDelete(sName);
            fnSetSavedFiles(prev => prev.filter(f => f !== sName));
        }
    };

    return (
        <InfoModal title={sMode === 'save' ? fnT('storage.saveMode') : fnT('storage.loadMode')} onClose={fnOnClose}>
            <div className="space-y-6">
                {sMode === 'save' && (
                    <div className="flex gap-2 items-end">
                        <Input 
                            label={fnT('storage.enterName')} 
                            value={sNameInput} 
                            onChange={e => fnSetNameInput(e.target.value)}
                            placeholder="My Character"
                        />
                        <Button onClick={fnHandleSave} disabled={!sNameInput.trim()} className="mb-[2px] h-[42px]">
                            {fnT('buttons.save')}
                        </Button>
                    </div>
                )}

                <div className="border-t border-gray-700 pt-4">
                    <h4 className="text-gray-400 font-bold mb-3 uppercase text-xs tracking-wider">{fnT('storage.savedCharacters')}</h4>
                    {aSavedFiles.length === 0 ? (
                        <p className="text-gray-500 italic text-center py-4">{fnT('storage.noSaves')}</p>
                    ) : (
                        <ul className="space-y-2 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                            {aSavedFiles.map(sName => (
                                <li 
                                    key={sName} 
                                    onClick={() => {
                                        if (sMode === 'load') {
                                            fnOnLoad(sName);
                                            fnOnClose();
                                        } else {
                                            fnSetNameInput(sName);
                                        }
                                    }}
                                    className={`
                                        flex justify-between items-center p-3 rounded border cursor-pointer transition-colors
                                        ${sMode === 'save' && sNameInput === sName 
                                            ? 'bg-red-900/30 border-red-500 text-white' 
                                            : 'bg-gray-800 border-gray-700 hover:bg-gray-700 hover:border-gray-600'}
                                    `}
                                >
                                    <span className="font-bold">{sName}</span>
                                    <button 
                                        onClick={(e) => fnHandleDelete(sName, e)}
                                        className="p-1 hover:bg-red-900 rounded text-gray-500 hover:text-white transition-colors"
                                        title={fnT('buttons.delete')}
                                    >
                                        <TrashIcon />
                                    </button>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>
            </div>
        </InfoModal>
    );
};

// --- NEW ALLOCATOR COMPONENT --- //
interface PointAllocatorProps {
    items: string[];
    values: Record<string, number>;
    onChange: (item: string, value: number) => void;
    pool: number[];
    translationPrefix?: string;
    baseValue?: number; // 1 for attributes, 0 for skills
    customRenderer?: (item: string) => React.ReactNode;
    renderAfterItem?: (item: string, value: number) => React.ReactNode;
}

const PointAllocator: React.FC<PointAllocatorProps> = ({ items: aItems, values: oValues, onChange: fnOnChange, pool: aPool, translationPrefix: sTranslationPrefix, baseValue: nBaseValue = 0, customRenderer: fnCustomRenderer, renderAfterItem: fnRenderAfterItem }) => {
    const { t: fnT } = useI18n();
    const [sActiveItem, fnSetActiveItem] = useState<string | null>(null);

    // Sort pool desc to prioritize showing higher numbers
    const aSortedPool = useMemo(() => [...aPool].sort((a, b) => b - a), [aPool]);

    // Get all currently assigned values to check against the pool
    const aAssignedValues = useMemo(() => aItems.map(sItem => oValues[sItem] || nBaseValue).filter(v => v > nBaseValue), [oValues, aItems, nBaseValue]);

    // Calculate usage for visuals
    const oPoolUsage = useMemo(() => {
        const oCounts = aSortedPool.reduce((oAcc, nVal) => {
            oAcc[nVal] = (oAcc[nVal] || 0) + 1;
            return oAcc;
        }, {} as Record<number, number>);

        const oUsed = aAssignedValues.reduce((oAcc, nVal) => {
            oAcc[nVal] = (oAcc[nVal] || 0) + 1;
            return oAcc;
        }, {} as Record<number, number>);

        // Calculate available counts for the selector logic
        const oAvailable = { ...oCounts };
        Object.keys(oUsed).forEach(k => {
            const nKey = parseInt(k);
            if (oAvailable[nKey]) {
                 oAvailable[nKey] = Math.max(0, oAvailable[nKey] - oUsed[nKey]);
            }
        });

        return { counts: oCounts, used: oUsed, available: oAvailable };
    }, [aSortedPool, aAssignedValues]);


    const fnGetGroups = () => {
        if (aItems.length <= 3) { // Disciplines or small groups
             return { [fnT('finishingTouches.disciplines.title')]: aItems };
        }
        // Assuming standardized order for attributes/skills in constant lists
        if (aItems.length === 9) { // Attributes
            return {
                [fnT('characterSheet.attributes.physical')]: aItems.slice(0, 3),
                [fnT('characterSheet.attributes.social')]: aItems.slice(3, 6),
                [fnT('characterSheet.attributes.mental')]: aItems.slice(6, 9)
            };
        } else { // Skills
             return {
                [fnT('characterSheet.skills.physical')]: aItems.slice(0, 9),
                [fnT('characterSheet.skills.social')]: aItems.slice(9, 18),
                [fnT('characterSheet.skills.mental')]: aItems.slice(18, 27)
            };
        }
    };

    const oGroups = fnGetGroups();

    const bIsPoolComplete = Object.values(oPoolUsage.available).every(val => val === 0);

    const fnRenderPoolVisuals = () => {
        const aVisuals: React.ReactNode[] = [];
        const oTempUsed = { ...oPoolUsage.used };

        aSortedPool.forEach((nVal, nIdx) => {
             const bIsUsed = (oTempUsed[nVal] || 0) > 0;
             if (bIsUsed) oTempUsed[nVal]--;

             aVisuals.push(
                 <div key={nIdx} className={`
                    flex items-center justify-center w-10 h-10 rounded-full border-2 font-bold text-sm transition-all duration-500
                    ${bIsUsed
                        ? 'bg-gray-900 border-gray-700 text-gray-600 scale-90 shadow-inner'
                        : 'bg-red-900/40 border-red-500 text-red-300 shadow-[0_0_10px_rgba(220,38,38,0.4)] scale-105 animate-pulse'}
                 `}>
                     {nVal}
                 </div>
             );
        });
        return aVisuals;
    };

    return (
        <div className="space-y-6">
             {/* Visual Pool */}
            <div className={`bg-gray-900/80 p-6 rounded-lg border transition-colors duration-500 shadow-lg ${bIsPoolComplete ? 'border-green-900/50' : 'border-red-900/50'}`}>
                <span className={`text-sm font-bold uppercase tracking-[0.2em] block mb-4 text-center border-b pb-2 flex items-center justify-center gap-2 ${bIsPoolComplete ? 'text-green-500 border-green-900/30' : 'text-red-400 border-red-900/30'}`}>
                    {fnT('common.poolDistribution')}
                    {bIsPoolComplete && <CheckCircle />}
                </span>
                <div className="flex flex-wrap justify-center gap-3 mb-2">
                    {fnRenderPoolVisuals()}
                </div>
                <div className="text-center mt-2 text-xs text-gray-500 italic">
                    {fnT('common.poolLegend')}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {Object.entries(oGroups).map(([sGroupName, aGroupItems]) => (
                    <div key={sGroupName} className={Object.keys(oGroups).length === 1 ? "lg:col-span-3" : ""}>
                         {Object.keys(oGroups).length > 1 && (
                            <h3 className="text-red-500 font-bold text-lg mb-3 border-b border-gray-700 pb-1 font-cinzel">{sGroupName}</h3>
                         )}
                        <div className="space-y-3">
                            {aGroupItems.map(sItem => (
                                <div key={sItem} className="relative">
                                    <button
                                        onClick={() => fnSetActiveItem(sActiveItem === sItem ? null : sItem)}
                                        className={`w-full flex justify-between items-center p-3 rounded-md border transition-all duration-300 ${
                                            sActiveItem === sItem 
                                            ? 'bg-gray-800 border-red-500 ring-1 ring-red-500 shadow-lg' 
                                            : 'bg-gray-800/60 border-gray-700 hover:border-gray-500 hover:bg-gray-700'
                                        }`}
                                    >
                                        <span className="font-bold text-gray-200">
                                            {fnCustomRenderer ? fnCustomRenderer(sItem) : (sTranslationPrefix ? fnT(`${sTranslationPrefix}.${sItem}`) : sItem)}
                                        </span>
                                        <div className="flex items-center gap-3">
                                            <span className={`text-xl font-bold ${(oValues[sItem] || nBaseValue) > nBaseValue ? 'text-red-400' : 'text-gray-600'}`}>
                                                {oValues[sItem] || nBaseValue}
                                            </span>
                                            <div className="flex space-x-0.5">
                                                 {[...Array(5)].map((_, nI) => (
                                                    <div key={nI} className={`w-1.5 h-1.5 rounded-full ${(oValues[sItem] || nBaseValue) > nI ? 'bg-red-500' : 'bg-gray-800'}`}></div>
                                                ))}
                                            </div>
                                        </div>
                                    </button>

                                    {/* Render optional extra content (like power selector) */}
                                    {(oValues[sItem] || 0) > 0 && fnRenderAfterItem && (
                                        <div className="mt-2 ml-2">
                                            {fnRenderAfterItem(sItem, oValues[sItem])}
                                        </div>
                                    )}

                                    {/* Expanded Selection Area */}
                                    {sActiveItem === sItem && (
                                        <div className="absolute z-20 top-full left-0 right-0 mt-2 p-3 bg-gray-900 border border-red-900 rounded-lg shadow-2xl grid grid-cols-1 gap-2 animate-fadeIn">
                                             <button
                                                onClick={() => { fnOnChange(sItem, nBaseValue); fnSetActiveItem(null); }}
                                                className="w-full py-1 px-2 text-xs text-gray-400 hover:text-white hover:bg-red-900/30 border border-transparent hover:border-red-900 rounded transition-colors uppercase tracking-wider"
                                            >
                                                {fnT('common.clear')}
                                            </button>
                                            <div className="flex justify-center gap-2 flex-wrap">
                                                {[...new Set([...aPool, ...Object.keys(oPoolUsage.available).map(Number)])].sort((a,b) => b-a).map(nVal => {
                                                    const nCount = oPoolUsage.available[nVal] || 0;
                                                    const bIsCurrent = (oValues[sItem] || nBaseValue) === nVal;
                                                    // Only disable if pool is empty for this value AND it's not the current value
                                                    const bIsDisabled = nCount === 0 && !bIsCurrent;

                                                    return (
                                                        <button
                                                            key={nVal}
                                                            disabled={bIsDisabled}
                                                            onClick={() => { fnOnChange(sItem, nVal); fnSetActiveItem(null); }}
                                                            className={`
                                                                w-10 h-10 rounded-full border-2 font-bold flex items-center justify-center transition-all duration-200
                                                                ${bIsCurrent
                                                                    ? 'bg-red-600 border-red-400 text-white shadow-[0_0_10px_rgba(220,38,38,0.5)] scale-110'
                                                                    : bIsDisabled
                                                                        ? 'bg-gray-800 border-gray-700 text-gray-700 cursor-not-allowed opacity-50'
                                                                        : 'bg-gray-800 border-gray-500 text-gray-300 hover:border-red-400 hover:text-red-400 hover:bg-gray-700 hover:scale-105'}
                                                            `}
                                                        >
                                                            {nVal}
                                                        </button>
                                                    );
                                                })}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};


// --- DISCIPLINE POWER SELECTOR --- //
interface DisciplinePowerSelectorProps {
    disciplineKey: string;
    dots: number;
    selectedPowerIds: string[];
    onSelectPowers: (ids: string[]) => void;
    disciplineDetails: DisciplineDetail;
}

const DisciplinePowerSelector: React.FC<DisciplinePowerSelectorProps> = ({ disciplineKey: sDisciplineKey, dots: nDots, selectedPowerIds: aSelectedPowerIds, onSelectPowers: fnOnSelectPowers, disciplineDetails: oDisciplineDetails }) => {
    const { t: fnT } = useI18n();
    const [bIsOpen, fnSetIsOpen] = useState(false);

    // Group powers by level
    const oPowersByLevel = useMemo(() => {
        const oGroups: Record<number, DisciplinePower[]> = {};
        oDisciplineDetails.powers.forEach(p => {
            if (!oGroups[p.level]) oGroups[p.level] = [];
            oGroups[p.level].push(p);
        });
        return oGroups;
    }, [oDisciplineDetails]);

    const fnCheckValidity = useCallback((sTestId: string) => {
        // Construct hypothetical list
        const aTestList = [...aSelectedPowerIds, sTestId];

        // Map to levels
        const aLevels = aTestList.map(id => {
            return oDisciplineDetails.powers.find(p => p.id === id)?.level || 0;
        });

        // Sort Descending (Highest level first)
        aLevels.sort((a, b) => b - a);

        // Validation Rule: The Nth highest power (0-indexed) must be <= TotalDots - N
        // This effectively matches powers to "slots" where each dot provides a slot of level equal to the dot number.
        for (let i = 0; i < aLevels.length; i++) {
            if (aLevels[i] > nDots - i) return false;
        }
        return true;
    }, [aSelectedPowerIds, nDots, oDisciplineDetails]);

    const fnTogglePower = (sPowerId: string) => {
        if (aSelectedPowerIds.includes(sPowerId)) {
            fnOnSelectPowers(aSelectedPowerIds.filter(id => id !== sPowerId));
        } else {
            // Strictly check constraint before adding
            if (aSelectedPowerIds.length < nDots && fnCheckValidity(sPowerId)) {
                fnOnSelectPowers([...aSelectedPowerIds, sPowerId]);
            }
        }
    };

    const aSelectedPowersList = useMemo(() => {
        return oDisciplineDetails.powers.filter(p => aSelectedPowerIds.includes(p.id));
    }, [oDisciplineDetails, aSelectedPowerIds]);

    const bIsComplete = aSelectedPowerIds.length === nDots;
    const bIsOverLimit = aSelectedPowerIds.length > nDots;

    return (
        <div className="w-full mt-2">
            {/* Selected Powers Preview Chips */}
            {aSelectedPowersList.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-3">
                    {aSelectedPowersList.map(oPower => (
                        <div key={oPower.id} className="flex items-center text-xs bg-gray-900 border border-red-900/50 text-red-100 px-2 py-1 rounded shadow-sm">
                            <span className="font-bold mr-1 text-red-500">{oPower.level}</span>
                            <span>{oPower.name}</span>
                        </div>
                    ))}
                </div>
            )}

            <Button 
                variant={bIsComplete ? "secondary" : "primary"} 
                className={`
                    w-full text-xs py-2 flex justify-center items-center gap-2 group 
                    ${bIsOverLimit ? "bg-red-900 border-red-500 text-white animate-pulse" : bIsComplete ? "bg-gray-800 text-green-400 border border-green-900 hover:border-green-700" : "animate-pulse"}
                `}
                onClick={() => fnSetIsOpen(true)}
            >
                <span className="uppercase tracking-wider font-bold">{fnT('common.managePowers')}</span>
                <span className={`px-2 py-0.5 rounded-full text-[10px] ${bIsOverLimit ? 'bg-red-500 text-white' : bIsComplete ? 'bg-green-900/30 text-green-400' : 'bg-red-900/30 text-white'}`}>
                    {aSelectedPowerIds.length}/{nDots}
                </span>
            </Button>

            {bIsOpen && (
                <InfoModal title={`${oDisciplineDetails.name} - ${fnT('finishingTouches.disciplines.selectPowers')}`} onClose={() => fnSetIsOpen(false)}>
                    <div className="text-left space-y-6">
                        <div className="bg-gray-900 p-4 rounded-lg border border-gray-700 flex justify-between items-center sticky top-0 z-10 shadow-lg">
                            <div>
                                <h4 className="font-bold text-gray-200">{fnT('finishingTouches.disciplines.powersSelected', { count: aSelectedPowerIds.length, total: nDots })}</h4>
                                <p className="text-xs text-gray-400">{fnT('finishingTouches.disciplines.subtitle')}</p>
                            </div>
                            <Button onClick={() => fnSetIsOpen(false)} variant="primary" className="text-xs px-4">{fnT('buttons.confirm')}</Button>
                        </div>

                        {[1, 2, 3, 4, 5].map(nLevel => {
                            const aPowers = oPowersByLevel[nLevel];
                            if (!aPowers) return null;
                            const bIsLevelUnlock = nDots >= nLevel;

                            return (
                                <div key={nLevel} className={`relative pl-4 border-l-2 ${bIsLevelUnlock ? 'border-red-500' : 'border-gray-700'}`}>
                                    <div className={`absolute -left-[9px] top-0 w-4 h-4 rounded-full border-2 ${bIsLevelUnlock ? 'bg-red-500 border-red-500' : 'bg-gray-900 border-gray-700'}`}></div>
                                    <h4 className={`text-lg font-bold mb-3 ${bIsLevelUnlock ? 'text-red-400' : 'text-gray-600'}`}>
                                        {fnT('compendium.level')} {nLevel}
                                    </h4>

                                    <div className="grid grid-cols-1 gap-3">
                                        {aPowers.map(oPower => {
                                            const bIsSelected = aSelectedPowerIds.includes(oPower.id);
                                            // Can select if:
                                            // 1. Level is unlocked
                                            // 2. AND (Already selected OR (Slots available AND Selection maintains valid dot progression))
                                            const bCanSelect = bIsLevelUnlock && (bIsSelected || (aSelectedPowerIds.length < nDots && fnCheckValidity(oPower.id)));

                                            return (
                                                <div 
                                                    key={oPower.id} 
                                                    onClick={() => bCanSelect && fnTogglePower(oPower.id)}
                                                    className={`
                                                        p-4 rounded-lg border-2 cursor-pointer transition-all duration-200 relative group
                                                        ${bIsSelected 
                                                            ? 'bg-red-900/20 border-red-500 shadow-[0_0_10px_rgba(220,38,38,0.2)]' 
                                                            : bCanSelect 
                                                                ? 'bg-gray-800 border-gray-700 hover:border-gray-500 hover:bg-gray-700' 
                                                                : 'bg-gray-900/50 border-gray-800 cursor-not-allowed opacity-50'}
                                                    `}
                                                >
                                                    <div className="flex justify-between items-start mb-2">
                                                        <span className={`font-bold text-lg ${bIsSelected ? 'text-white' : 'text-gray-300 group-hover:text-red-300'}`}>{oPower.name}</span>
                                                        {bIsSelected && <div className="bg-red-500 rounded-full p-1"><CheckCircle /></div>}
                                                    </div>
                                                    <p className="text-sm text-gray-400 mb-3 leading-relaxed">{oPower.description}</p>
                                                    <div className="bg-black/30 p-2 rounded text-xs text-gray-500 font-mono border-l-2 border-gray-600">
                                                        <strong className="text-gray-400 block mb-1">{fnT('compendium.system')}:</strong>
                                                        {oPower.system}
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </InfoModal>
            )}
        </div>
    );
};


const App: React.FC = () => {
    // Load from localStorage on initialization
    const [oBaseCharacter, fnSetBaseCharacter] = useState<Character>(() => {
        if (typeof window !== 'undefined') {
            const sSaved = localStorage.getItem('vtm_character_v1');
            if (sSaved) {
                try {
                    const oParsed = JSON.parse(sSaved);
                    // Migration: Ensure disciplinePowers exists
                    if (!oParsed.disciplinePowers) oParsed.disciplinePowers = {};
                    return oParsed;
                } catch (e) {
                    console.error("Failed to load saved character", e);
                }
            }
        }
        return oInitialCharacter;
    });

    const [oCharacter, fnSetCharacter] = useState<Character>(oInitialCharacter);
    const [oSectionsOpen, fnSetSectionsOpen] = useState<Record<string, boolean>>({
        concept: true,
        clan: false,
        attributes: false,
        skills: false,
        finishing: false,
        sheet: false
    });

    const { t: fnT, locale: sLocale, setLocale: fnSetLocale } = useI18n();
    const [oModalContent, fnSetModalContent] = useState<{ title: string; content: React.ReactNode } | null>(null);
    const oFileInputRef = useRef<HTMLInputElement>(null);
    const [bStorageModalOpen, fnSetStorageModalOpen] = useState(false);
    const [sStorageMode, fnSetStorageMode] = useState<'save' | 'load'>('save');

    const aPredatorTypes = useMemo(() => fnGetPredatorTypes(fnT), [fnT]);

    // Save to localStorage whenever baseCharacter changes (Auto-save)
    useEffect(() => {
        localStorage.setItem('vtm_character_v1', JSON.stringify(oBaseCharacter));
    }, [oBaseCharacter]);

    // Calculate derived stats and merge predator bonuses
    useEffect(() => {
        const oPredator = oBaseCharacter.predatorType ? aPredatorTypes.find(p => p.name === oBaseCharacter.predatorType) : null;

        let oFinalChar = { ...oBaseCharacter };

        if(oPredator) {
            // Recalculate humanity
            oFinalChar.humanity = 7 + oPredator.humanityModifier;

            // Recalculate disciplines (cumulative)
            const oFinalDisciplines = { ...oBaseCharacter.disciplines };
            if (oPredator.disciplineAdd) {
                const { discipline, dots } = oPredator.disciplineAdd;
                oFinalDisciplines[discipline] = (oFinalDisciplines[discipline] || 0) + dots;
            }
            oFinalChar.disciplines = oFinalDisciplines;

            // Merge predator advantages/flaws with manually selected ones, avoiding duplicates
            const aUniquePredatorAdvantages = oPredator.advantages.filter(pAdv => !oBaseCharacter.advantages.some(cAdv => cAdv.name === pAdv.name));
             const aUniquePredatorFlaws = oPredator.flaws.filter(pFlaw => !oBaseCharacter.flaws.some(cFlaw => cFlaw.name === pFlaw.name));

            oFinalChar.advantages = [...oBaseCharacter.advantages, ...aUniquePredatorAdvantages];
            oFinalChar.flaws = [...oBaseCharacter.flaws, ...aUniquePredatorFlaws];
        } else {
            oFinalChar.humanity = 7;
        }

        fnSetCharacter(oFinalChar);
    }, [oBaseCharacter, aPredatorTypes]);


    const fnToggleLanguage = () => {
        fnSetLocale(sLocale === 'en' ? 'pt' : 'en');
    };

    const fnHandleShowDiscipline = useCallback((oDiscipline: DisciplineDetail) => {
        fnSetModalContent({
            title: oDiscipline.name,
            content: (
                <div className="space-y-4 text-left">
                    <p className="text-gray-400 italic">{oDiscipline.description}</p>
                    {oDiscipline.powers.map(oPower => (
                        <div key={oPower.level} className="border-t border-gray-700 pt-3">
                            <h4 className="font-bold text-red-400">
                                {fnT('compendium.level')} {oPower.level}: {oPower.name}
                            </h4>
                            <p className="text-sm text-gray-300 mt-1">{oPower.description}</p>
                            <p className="text-xs text-gray-500 mt-2"><strong className="font-bold">{fnT('compendium.system')}:</strong> {oPower.system}</p>
                        </div>
                    ))}
                </div>
            )
        });
    }, [fnT]);

    useEffect(() => {
        document.documentElement.lang = sLocale;
    }, [sLocale]);


    const fnUpdateBaseCharacter = useCallback(<K extends keyof Character>(sKey: K, value: Character[K]) => {
        fnSetBaseCharacter(prev => ({ ...prev, [sKey]: value }));
    }, []);

    const fnToggleSection = (sKey: string) => {
        fnSetSectionsOpen(prev => ({ ...prev, [sKey]: !prev[sKey] }));
    };

    const fnExpandAll = () => {
        fnSetSectionsOpen(Object.keys(oSectionsOpen).reduce((oAcc, sKey) => ({...oAcc, [sKey]: true}), {}));
    };

    const fnCollapseAll = () => {
         fnSetSectionsOpen(Object.keys(oSectionsOpen).reduce((oAcc, sKey) => ({...oAcc, [sKey]: false}), {}));
    };

    const fnHandleDownload = () => {
        const sDataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(oBaseCharacter, null, 2));
        const oDownloadAnchorNode = document.createElement('a');
        oDownloadAnchorNode.setAttribute("href", sDataStr);
        oDownloadAnchorNode.setAttribute("download", `${oBaseCharacter.name || 'character'}.json`);
        document.body.appendChild(oDownloadAnchorNode);
        oDownloadAnchorNode.click();
        oDownloadAnchorNode.remove();
    };

    const fnHandleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const oFile = e.target.files?.[0];
        if (!oFile) return;
        const oReader = new FileReader();
        oReader.onload = (event) => {
            try {
                const oParsed = JSON.parse(event.target?.result as string);
                // Basic validation checks if critical fields exist
                if (oParsed.attributes && oParsed.skills) {
                    if (!oParsed.disciplinePowers) oParsed.disciplinePowers = {};
                    fnSetBaseCharacter(oParsed);
                } else {
                    alert("Invalid character file structure.");
                }
            } catch (error) {
                console.error("Error parsing JSON", error);
                alert("Invalid character file.");
            }
        };
        oReader.readAsText(oFile);
        // Reset input so same file can be selected again
        e.target.value = '';
    };

    const fnHandleReset = () => {
        if (window.confirm("Are you sure you want to reset? All data will be lost.")) {
            fnSetBaseCharacter(oInitialCharacter);
            localStorage.removeItem('vtm_character_v1');
        }
    };

    const fnHandleStorageSave = (sName: string) => {
        localStorage.setItem(`vtm_save_${sName}`, JSON.stringify(oBaseCharacter));
    };

    const fnHandleStorageLoad = (sName: string) => {
        const sSaved = localStorage.getItem(`vtm_save_${sName}`);
        if (sSaved) {
            try {
                const oParsed = JSON.parse(sSaved);
                if (!oParsed.disciplinePowers) oParsed.disciplinePowers = {};
                fnSetBaseCharacter(oParsed);
            } catch (e) {
                console.error("Failed to load saved character", e);
            }
        }
    };

    const fnHandleStorageDelete = (sName: string) => {
        localStorage.removeItem(`vtm_save_${sName}`);
    }

    return (
        <div className="min-h-screen bg-gray-900 text-white p-4 md:p-8">
            <div className="container mx-auto max-w-5xl relative">
                <header className="text-center mb-8">
                    <h1 className="text-4xl md:text-5xl font-bold text-red-500 tracking-wider font-cinzel">{fnT('app.title')}</h1>
                    <p className="text-gray-400 mt-2 font-lato">{fnT('app.subtitle')}</p>
                </header>

                <div className="absolute top-0 right-0 flex gap-2">
                     <Button onClick={() => { fnSetStorageMode('save'); fnSetStorageModalOpen(true); }} variant="secondary" className="px-2 py-1 md:px-3 flex items-center gap-2 text-sm" title={fnT('buttons.save')}>
                        <FloppyDiskIcon /> <span className="hidden lg:inline">{fnT('buttons.save')}</span>
                     </Button>
                     <Button onClick={() => { fnSetStorageMode('load'); fnSetStorageModalOpen(true); }} variant="secondary" className="px-2 py-1 md:px-3 flex items-center gap-2 text-sm" title={fnT('buttons.load')}>
                        <FolderOpenIcon /> <span className="hidden lg:inline">{fnT('buttons.load')}</span>
                     </Button>
                     <div className="w-px h-6 bg-gray-700 mx-1 self-center"></div>
                     <Button onClick={fnHandleDownload} variant="secondary" className="px-2 py-1 md:px-3 flex items-center gap-2 text-sm" title={fnT('buttons.export')}>
                        <ArrowDownTrayIcon /> <span className="hidden lg:inline">{fnT('buttons.export')}</span>
                     </Button>
                     <Button onClick={() => oFileInputRef.current?.click()} variant="secondary" className="px-2 py-1 md:px-3 flex items-center gap-2 text-sm" title={fnT('buttons.import')}>
                        <ArrowUpTrayIcon /> <span className="hidden lg:inline">{fnT('buttons.import')}</span>
                     </Button>
                     <input type="file" ref={oFileInputRef} onChange={fnHandleFileUpload} className="hidden" accept=".json" />
                     <div className="w-px h-6 bg-gray-700 mx-1 self-center"></div>
                     <Button onClick={fnHandleReset} variant="danger" className="px-2 py-1 md:px-3 flex items-center gap-2 text-sm" title={fnT('buttons.reset')}>
                        <ResetIcon />
                     </Button>
                     <Button onClick={fnToggleLanguage} variant="secondary" className="px-3 py-1 ml-1">
                        {sLocale === 'en' ? 'PT' : 'EN'}
                    </Button>
                </div>

                <div className="flex justify-end gap-2 mb-4 mt-8 md:mt-0">
                    <Button onClick={fnExpandAll} variant="secondary" className="text-sm px-3 py-1">{fnT('buttons.expandAll')}</Button>
                    <Button onClick={fnCollapseAll} variant="secondary" className="text-sm px-3 py-1">{fnT('buttons.collapseAll')}</Button>
                </div>

                <main className="space-y-4">

                    <CollapsibleSection title={fnT('steps.concept')} isOpen={oSectionsOpen.concept} onToggle={() => fnToggleSection('concept')}>
                        <StepConcept character={oBaseCharacter} updateCharacter={fnUpdateBaseCharacter} />
                    </CollapsibleSection>

                    <CollapsibleSection title={fnT('steps.clan')} isOpen={oSectionsOpen.clan} onToggle={() => fnToggleSection('clan')}>
                        <StepClan character={oBaseCharacter} updateCharacter={fnUpdateBaseCharacter} />
                    </CollapsibleSection>

                    <CollapsibleSection title={fnT('steps.attributes')} isOpen={oSectionsOpen.attributes} onToggle={() => fnToggleSection('attributes')}>
                        <StepAttributes character={oBaseCharacter} updateCharacter={fnUpdateBaseCharacter} />
                    </CollapsibleSection>

                    <CollapsibleSection title={fnT('steps.skills')} isOpen={oSectionsOpen.skills} onToggle={() => fnToggleSection('skills')}>
                        <StepSkills character={oBaseCharacter} updateCharacter={fnUpdateBaseCharacter} predatorTypes={aPredatorTypes} />
                    </CollapsibleSection>

                    <CollapsibleSection title={fnT('steps.finishingTouches')} isOpen={oSectionsOpen.finishing} onToggle={() => fnToggleSection('finishing')}>
                        <StepFinishingTouches 
                            character={oCharacter} // Pass derived character for logic (e.g. total dots)
                            baseCharacter={oBaseCharacter} // Pass base character for updating
                            updateCharacter={fnUpdateBaseCharacter} 
                            onShowDiscipline={fnHandleShowDiscipline} 
                            predatorTypes={aPredatorTypes} 
                        />
                    </CollapsibleSection>

                    <div className="my-8">
                        <CharacterSummary character={oCharacter} />
                    </div>

                    <CollapsibleSection title={fnT('steps.sheet')} isOpen={oSectionsOpen.sheet} onToggle={() => fnToggleSection('sheet')}>
                         <CharacterSheet 
                            character={oCharacter} 
                            onUpdateHunger={(nVal) => fnUpdateBaseCharacter('hunger', nVal)}
                        />
                    </CollapsibleSection>

                </main>

                <footer className="mt-12 text-center text-gray-600 text-sm">
                    Vampire: The Masquerade 5th Edition Fan App
                </footer>
            </div>
            {oModalContent && (
                <InfoModal title={oModalContent.title} onClose={() => fnSetModalContent(null)}>
                    {oModalContent.content}
                </InfoModal>
            )}

            {bStorageModalOpen && (
                <StorageModal 
                    mode={sStorageMode}
                    onClose={() => fnSetStorageModalOpen(false)}
                    currentName={oBaseCharacter.name}
                    onSave={fnHandleStorageSave}
                    onLoad={fnHandleStorageLoad}
                    onDelete={fnHandleStorageDelete}
                />
            )}
        </div>
    );
};

