    const fnHandleClanSelect = (sClan: Clan) => {
        if (oCharacter.clan !== sClan) {
            fnUpdateCharacter('clan', sClan);
            // Reset disciplines and powers when clan changes to prevent invalid state
            fnUpdateCharacter('disciplines', {});
            fnUpdateCharacter('disciplinePowers', {});
        }
    };

    // Determine which lore quote to show
    const sQuoteKey = sHoveredClan || oCharacter.clan;
    const sQuoteText = sQuoteKey ? fnT(`lore.clans.${sQuoteKey}`) : fnT('lore.intro');
    const sQuoteSource = sQuoteKey ? oClanDetails[sQuoteKey].name : undefined;

    const oSelectedClanDetails = oCharacter.clan ? oClanDetails[oCharacter.clan] : null;

    return(
