                                <div className="mb-2">
                                    <h3 className="text-base font-bold text-red-500 mb-1">{oDetails.name}</h3>
                                    <p className={`text-xs text-gray-400 ${bShowDetails ? '' : 'line-clamp-2'}`}>{oDetails.description}</p>
