                                            <span className="text-red-400 font-bold block text-[10px] uppercase tracking-wider">{fnT('characterSheet.disciplines')}</span>
                                            <span className="text-gray-300">{oDetails.disciplines.join(', ')}</span>
                                        </div>
                                        <div>
                                            <span className="text-red-400 font-bold block text-[10px] uppercase tracking-wider">{fnT('characterSheet.clanBane')}</span>
                                            <span className="text-gray-300 leading-tight">{oDetails.bane}</span>
                                        </div>
                                        <div>
                                            <span className="text-red-400 font-bold block text-[10px] uppercase tracking-wider">{fnT('characterSheet.clanCompulsion')}</span>
                                            <span className="text-gray-300 leading-tight">{oDetails.compulsion}</span>
                                        </div>
                                    </div>
                                )}
                            </Card>
                        </div>
                    )
                })}
            </div>

             {/* Dedicated Details Section for Selected Clan */}
             {oSelectedClanDetails && (
                <div className="mt-6 bg-gray-800/50 border border-red-900/30 rounded-lg p-6 animate-fadeIn">
                    <h3 className="text-2xl font-cinzel font-bold text-red-500 mb-2">{oSelectedClanDetails.name}</h3>
                    <p className="text-gray-300 italic mb-6 border-b border-gray-700 pb-4">{oSelectedClanDetails.description}</p>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                             <h4 className="text-red-400 font-bold uppercase tracking-wider text-sm mb-3 border-b border-red-900/30 pb-1">{fnT('characterSheet.clanBane')}</h4>
                             <p className="text-gray-300 leading-relaxed bg-gray-900/50 p-3 rounded border border-gray-800">{oSelectedClanDetails.bane}</p>
                        </div>
                         <div>
                             <h4 className="text-red-400 font-bold uppercase tracking-wider text-sm mb-3 border-b border-red-900/30 pb-1">{fnT('characterSheet.clanCompulsion')}</h4>
                             <p className="text-gray-300 leading-relaxed bg-gray-900/50 p-3 rounded border border-gray-800">{oSelectedClanDetails.compulsion}</p>
