const AdvantageFlawSelector: React.FC<{
    baseCharacter: Character;
    updateCharacter: <K extends keyof Character>(key: K, value: Character[K]) => void;
    predatorType: PredatorTypeDetail | null;
}> = ({ baseCharacter: oCharacter, updateCharacter: fnUpdateCharacter, predatorType: oPredatorType }) => {
    const { t: fnT } = useI18n();
    const aAdvantagesFlawsList = useMemo(() => fnGetAdvantagesAndFlaws(fnT), [fnT]);
    const [sExpandedItem, fnSetExpandedItem] = useState<string | null>(null);

    // Custom Trait State
    const [sCustomName, fnSetCustomName] = useState('');
    const [nCustomDots, fnSetCustomDots] = useState(1);
    const [sCustomType, fnSetCustomType] = useState<'advantage' | 'flaw'>('advantage');

    const aAdvantagesList = aAdvantagesFlawsList.filter(item => item.type === 'advantage');
    const aFlawsList = aAdvantagesFlawsList.filter(item => item.type === 'flaw');

    // Calculate ONLY base character points
    const nSpentAdvantagePoints = useMemo(() => oCharacter.advantages.reduce((sum, adv) => sum + adv.cost, 0), [oCharacter.advantages]);
    const nSpentFlawPoints = useMemo(() => oCharacter.flaws.reduce((sum, flaw) => sum + flaw.cost, 0), [oCharacter.flaws]);

    const fnAddTrait = (oTrait: AdvantageFlaw, nCost: number) => {
        const bIsAdvantage = oTrait.type === 'advantage';
        const aList = bIsAdvantage ? oCharacter.advantages : oCharacter.flaws;
        const fnUpdateList = bIsAdvantage ? (l: AdvantageFlaw[]) => fnUpdateCharacter('advantages', l) : (l: AdvantageFlaw[]) => fnUpdateCharacter('flaws', l);
        const nLimit = bIsAdvantage ? 7 : 2;

        const nExistingIndex = aList.findIndex(item => item.name === oTrait.name);
        const oExistingItem = aList[nExistingIndex];

        // If clicking the exact same level, do nothing
        if (oExistingItem && oExistingItem.cost === nCost) return;

        // Calculate cost difference
        const nOldCost = oExistingItem ? oExistingItem.cost : 0;
        const nCurrentTotal = bIsAdvantage ? nSpentAdvantagePoints : nSpentFlawPoints;
        const nNewTotal = nCurrentTotal - nOldCost + nCost;

        if (nNewTotal <= nLimit) {
            const oNewItem = { ...oTrait, cost: nCost };
            let aNewList = [...aList];

            if (nExistingIndex >= 0) {
                aNewList[nExistingIndex] = oNewItem;
            } else {
                aNewList.push(oNewItem);
            }
            fnUpdateList(aNewList);
        }
    }

    const fnAddCustomTrait = () => {
        if (!sCustomName.trim()) return;
        const oTrait: AdvantageFlaw = {
            name: sCustomName,
            description: 'Custom Trait',
            cost: nCustomDots,
            type: sCustomType,
            levels: [nCustomDots]
        };
        fnAddTrait(oTrait, nCustomDots);
        fnSetCustomName('');
        fnSetCustomDots(1);
    };

    const fnRemoveTrait = (nIndex: number, sType: 'advantage' | 'flaw') => {
         const aList = sType === 'advantage' ? oCharacter.advantages : oCharacter.flaws;
         const aNewList = [...aList];
         aNewList.splice(nIndex, 1);
         if (sType === 'advantage') fnUpdateCharacter('advantages', aNewList);
         else fnUpdateCharacter('flaws', aNewList);
    }

    const fnRenderSelector = (aList: AdvantageFlaw[], aSelectedList: AdvantageFlaw[], nCurrentPoints: number, nLimit: number, sType: 'advantage' | 'flaw') => {
        return (
            <div className="space-y-2">
                {aList.map(oItem => {
                    const bIsExpanded = sExpandedItem === oItem.name;
                    const aLevels = oItem.levels || [oItem.cost];
                    const oSelectedItem = aSelectedList.find(s => s.name === oItem.name);

                    return (
                        <div key={oItem.name} className="border border-gray-700 rounded-md bg-gray-800 overflow-hidden">
                            <div 
                                className={`p-2 flex justify-between items-center cursor-pointer hover:bg-gray-700 transition-colors ${bIsExpanded ? 'bg-gray-700' : ''}`}
                                onClick={() => fnSetExpandedItem(bIsExpanded ? null : oItem.name)}
                            >
                                <span className="font-bold text-gray-200">{oItem.name}</span>
                                <div className="flex items-center gap-2">
                                    {oSelectedItem && <span className="text-xs text-red-400 font-bold">({oSelectedItem.cost})</span>}
                                    <span className="text-xs text-gray-400">{aLevels.length > 1 ? fnT('common.value') : `${fnT('common.value')}: ${aLevels[0]}`}</span>
                                </div>
                            </div>

                            {bIsExpanded && (
                                <div className="p-2 bg-gray-900 border-t border-gray-700 animate-fadeIn">
                                    <p className="text-xs text-gray-400 mb-2">{oItem.description}</p>
                                    <div className="flex flex-wrap gap-2 justify-end">
                                        {aLevels.map(nLevel => {
                                            const bIsSelected = oSelectedItem?.cost === nLevel;
                                            const nCostDiff = nLevel - (oSelectedItem ? oSelectedItem.cost : 0);
                                            const bDisabled = (nCurrentPoints + nCostDiff > nLimit) && !bIsSelected;

                                            return (
                                                <button
                                                    key={nLevel}
                                                    disabled={bDisabled}
                                                    onClick={() => fnAddTrait(oItem, nLevel)}
                                                    className={`
                                                        w-8 h-8 rounded-full border font-bold text-sm flex items-center justify-center transition-all duration-200
                                                        ${bIsSelected 
                                                            ? 'bg-red-600 border-red-400 text-white shadow-[0_0_10px_rgba(220,38,38,0.5)] scale-110' 
                                                            : bDisabled 
                                                                ? 'border-gray-700 text-gray-600 cursor-not-allowed opacity-50' 
                                                                : 'border-red-500 text-red-400 hover:bg-red-900 hover:text-white hover:scale-105'}
                                                    `}
                                                >
                                                    {nLevel}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    };

    return (
        <div className="md:col-span-2 grid grid-cols-1 lg:grid-cols-2 gap-8 border-t border-red-900/30 pt-8">

            {/* Custom Trait Section */}
            <div className="lg:col-span-2 bg-gray-900/50 p-4 rounded border border-gray-700">
                <h4 className="text-sm font-bold text-red-400 uppercase tracking-wider mb-4">Add Custom Advantage / Flaw</h4>
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-grow">
                        <Input 
                            label="Trait Name" 
                            value={sCustomName} 
                            onChange={(e) => fnSetCustomName(e.target.value)} 
                            placeholder="e.g. Unbondable" 
                        />
                    </div>
                    <div className="w-24">
                        <label className="block text-sm font-medium text-gray-300 mb-1">Dots</label>
                        <select 
                            value={nCustomDots} 
                            onChange={(e) => fnSetCustomDots(parseInt(e.target.value))}
                            className="w-full bg-gray-800 border border-gray-600 rounded-md shadow-sm px-2 py-2 text-white focus:outline-none focus:ring-2 focus:ring-red-500"
                        >
                            {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n}</option>)}
                        </select>
                    </div>
                    <div className="w-32">
                        <label className="block text-sm font-medium text-gray-300 mb-1">Type</label>
                        <select 
                            value={sCustomType} 
                            onChange={(e) => fnSetCustomType(e.target.value as 'advantage' | 'flaw')}
                            className="w-full bg-gray-800 border border-gray-600 rounded-md shadow-sm px-2 py-2 text-white focus:outline-none focus:ring-2 focus:ring-red-500"
                        >
                            <option value="advantage">Advantage</option>
                            <option value="flaw">Flaw</option>
                        </select>
                    </div>
                    <Button onClick={fnAddCustomTrait} disabled={!sCustomName} className="h-[42px] mb-[1px]">
                        {fnT('buttons.add')}
                    </Button>
                </div>
            </div>

            {/* Predator Bonuses (Read Only) */}
            {oPredatorType && (oPredatorType.advantages.length > 0 || oPredatorType.flaws.length > 0) && (
                 <div className="lg:col-span-2 bg-gray-900/50 p-4 rounded border border-red-900/50">
                    <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Predator Type Bonuses (Free)</h4>
                    <div className="flex flex-wrap gap-2">
                        {oPredatorType.advantages.map((adv, i) => (
                            <span key={`p-adv-${i}`} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-900/30 text-green-400 border border-green-900">
                                {adv.name} ({adv.cost})
                            </span>
                        ))}
                        {oPredatorType.flaws.map((flaw, i) => (
                            <span key={`p-flaw-${i}`} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-900/30 text-red-400 border border-red-900">
                                {flaw.name} ({flaw.cost})
                            </span>
                        ))}
                    </div>
                 </div>
            )}

            <div>
                <h3 className="text-lg font-bold text-red-400 mb-2">{fnT('finishingTouches.advantages.title')} ({nSpentAdvantagePoints}/7)</h3>

                {/* Selected Advantages */}
                <div className="space-y-2 p-2 border border-gray-700 rounded-md bg-gray-900 min-h-[100px] mb-4">
                    {oCharacter.advantages.length === 0 && <p className="text-gray-600 italic text-sm p-2">{fnT('common.noneListed')}</p>}
                    {oCharacter.advantages.map((oAdv, nIdx) => (
                        <div key={`${oAdv.name}-${nIdx}`} className="flex justify-between items-center bg-gray-800 p-2 rounded border border-gray-700">
                            <div>
                                <span className="font-bold text-sm">{oAdv.name}</span>
                                <div className="flex space-x-1 mt-1">
                                    {[...Array(oAdv.cost)].map((_, nI) => (
                                        <div key={nI} className="w-2 h-2 rounded-full bg-red-500"></div>
                                    ))}
                                </div>
                            </div>
                            <Button variant="danger" className="px-2 py-0.5 text-xs h-6" onClick={() => fnRemoveTrait(nIdx, 'advantage')}>X</Button>
                        </div>
                    ))}
                </div>

                <div className="max-h-96 overflow-y-auto custom-scrollbar pr-2">
                     <h4 className="text-xs uppercase text-gray-500 font-bold mb-2 tracking-wider">{fnT('common.available')} {fnT('finishingTouches.advantages.title')}</h4>
                    {fnRenderSelector(aAdvantagesList, oCharacter.advantages, nSpentAdvantagePoints, 7, 'advantage')}
                </div>
            </div>

            <div>
                <h3 className="text-lg font-bold text-red-400 mb-2">{fnT('finishingTouches.flaws.title')} ({nSpentFlawPoints}/2)</h3>

                {/* Selected Flaws */}
                <div className="space-y-2 p-2 border border-gray-700 rounded-md bg-gray-900 min-h-[100px] mb-4">
                    {oCharacter.flaws.length === 0 && <p className="text-gray-600 italic text-sm p-2">{fnT('common.noneListed')}</p>}
                     {oCharacter.flaws.map((oFlaw, nIdx) => (
                        <div key={`${oFlaw.name}-${nIdx}`} className="flex justify-between items-center bg-gray-800 p-2 rounded border border-gray-700">
                            <div>
                                <span className="font-bold text-sm">{oFlaw.name}</span>
                                 <div className="flex space-x-1 mt-1">
                                    {[...Array(oFlaw.cost)].map((_, nI) => (
                                        <div key={nI} className="w-2 h-2 rounded-full bg-red-500"></div>
                                    ))}
                                </div>
                            </div>
                            <Button variant="danger" className="px-2 py-0.5 text-xs h-6" onClick={() => fnRemoveTrait(nIdx, 'flaw')}>X</Button>
                        </div>
                    ))}
                </div>

                 <div className="max-h-96 overflow-y-auto custom-scrollbar pr-2">
                    <h4 className="text-xs uppercase text-gray-500 font-bold mb-2 tracking-wider">{fnT('common.available')} {fnT('finishingTouches.flaws.title')}</h4>
                    {fnRenderSelector(aFlawsList, oCharacter.flaws, nSpentFlawPoints, 2, 'flaw')}
                </div>
            </div>
        </div>
    )
}

