const SpecialtySelector: React.FC<{
    character: Character;
    updateCharacter: <K extends keyof Character>(key: K, value: Character[K]) => void;
    predatorType: PredatorTypeDetail | null;
}> = ({ character: oCharacter, updateCharacter: fnUpdateCharacter, predatorType: oPredatorType }) => {
    const { t: fnT } = useI18n();
    const [aUserSpecialties, fnSetUserSpecialties] = useState<Specialty[]>([]);
    const [oPredatorChoice, fnSetPredatorChoice] = useState<Specialty | null>(null);
    const [bIsAdding, fnSetIsAdding] = useState(false);
    const [sNewSpecialtySkill, fnSetNewSpecialtySkill] = useState<string>("");
    const [sNewSpecialtyName, fnSetNewSpecialtyName] = useState<string>("");

    const aPredatorFixedSpecialties = oPredatorType?.specialties || [];
    const aPredatorOptions = oPredatorType?.specialtyOptions || [];

    // Sync internal state with character state
    useEffect(() => {
        if (aPredatorOptions.length > 0 && !oPredatorChoice) {
            const oExistingChoice = oCharacter.specialties.find(s => 
                aPredatorOptions.some(opt => opt.skill === s.skill && opt.name === s.name)
            );
            if (oExistingChoice) {
                fnSetPredatorChoice(oExistingChoice);
            }
        }

        const aNonPredator = oCharacter.specialties.filter(s => 
            !aPredatorFixedSpecialties.some(ps => ps.skill === s.skill && ps.name === s.name) &&
            (!oPredatorChoice || (s.skill !== oPredatorChoice.skill || s.name !== oPredatorChoice.name))
        );

         const aUniqueNonPredator = aNonPredator.filter((v,i,a)=>a.findIndex(v2=>(v2.skill===v.skill && v2.name===v.name))===i);

         if (JSON.stringify(aUniqueNonPredator) !== JSON.stringify(aUserSpecialties)) {
             fnSetUserSpecialties(aUniqueNonPredator);
         }
    }, [oCharacter.predatorType]); 


    // Update character whenever local parts change
    useEffect(() => {
        const aAllSpecialties = [
            ...aPredatorFixedSpecialties,
            ...(oPredatorChoice ? [oPredatorChoice] : []),
            ...aUserSpecialties
        ];
        const bIsDifferent = JSON.stringify(aAllSpecialties) !== JSON.stringify(oCharacter.specialties);
        if (bIsDifferent) {
            fnUpdateCharacter('specialties', aAllSpecialties);
        }

    }, [aPredatorFixedSpecialties, oPredatorChoice, aUserSpecialties, fnUpdateCharacter]);


    const fnRemoveUserSpecialty = (nIndex: number) => {
        const aNewList = [...aUserSpecialties];
        aNewList.splice(nIndex, 1);
        fnSetUserSpecialties(aNewList);
    }

    const fnHandleAddSpecialty = () => {
        if (sNewSpecialtySkill && sNewSpecialtyName) {
            fnSetUserSpecialties([...aUserSpecialties, { skill: sNewSpecialtySkill as Skill, name: sNewSpecialtyName }]);
            fnSetIsAdding(false);
            fnSetNewSpecialtyName("");
            fnSetNewSpecialtySkill("");
        }
    };

    const aAvailableSkills = aSkillList.filter(s => oCharacter.skills[s] > 0);

    return (
        <div className="md:col-span-2 border-t border-red-900/30 pt-8">
            <h3 className="text-xl font-bold text-red-400 mb-2">{fnT('finishingTouches.specialties.title')}</h3>
            <p className="text-sm text-gray-400 mb-4">{fnT('finishingTouches.specialties.subtitle')}</p>

            <div className="space-y-6">

                {/* Predator Section */}
                {(aPredatorFixedSpecialties.length > 0 || aPredatorOptions.length > 0) && (
                    <div className="bg-gray-900/50 p-4 rounded border border-gray-800">
                        <h4 className="text-sm font-bold text-gray-300 uppercase tracking-wider mb-3">{fnT('finishingTouches.specialties.fromPredator')}</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                            {/* Fixed */}
                            {aPredatorFixedSpecialties.map((oSpec, nI) => (
                                <SpecialtyCard key={nI} skill={oSpec.skill} name={oSpec.name} isFixed={true} />
                            ))}

                            {/* Optional */}
                            {aPredatorOptions.length > 0 && (
                                <div className="p-3 border border-red-900/40 rounded-lg bg-gray-800/50 relative">
                                    <div className="absolute top-1 right-2 text-[10px] text-red-400 uppercase font-bold tracking-wider">
                                        {fnT('finishingTouches.specialties.choice')}
                                    </div>
                                    <div className="flex flex-col gap-2 mt-4">
                                        {aPredatorOptions.map((oOpt, nI) => (
                                            <label key={nI} className={`flex items-center space-x-2 cursor-pointer p-2 rounded transition-colors ${oPredatorChoice?.name === oOpt.name ? 'bg-red-900/30 ring-1 ring-red-500' : 'hover:bg-gray-700'}`}>
                                                <input 
                                                    type="radio" 
                                                    name="predatorSpecialty" 
                                                    className="form-radio h-4 w-4 text-red-600 focus:ring-red-500 bg-gray-900 border-gray-600"
                                                    checked={oPredatorChoice?.skill === oOpt.skill && oPredatorChoice?.name === oOpt.name}
                                                    onChange={() => fnSetPredatorChoice(oOpt)}
                                                />
                                                <div className="text-sm leading-tight">
                                                    <span className="font-bold text-gray-300">{fnT(`skills.list.${oOpt.skill}`)}</span> <span className="text-gray-500 italic">({oOpt.name})</span>
                                                </div>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Free / User Section */}
                <div>
                     <div className="flex justify-between items-center mb-3">
                        <h4 className="text-sm font-bold text-gray-300 uppercase tracking-wider">{fnT('finishingTouches.specialties.free')}</h4>
                     </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                        {aUserSpecialties.map((oSpec, nIdx) => (
                             <SpecialtyCard 
                                key={nIdx} 
                                skill={oSpec.skill} 
                                name={oSpec.name} 
                                onDelete={() => fnRemoveUserSpecialty(nIdx)} 
                             />
                        ))}
                        <SpecialtyCard 
                            isEmpty={true} 
                            onClick={() => fnSetIsAdding(true)} 
                            label={fnT('finishingTouches.specialties.addSpecialty')}
                        />
                    </div>
                </div>
            </div>

            {/* Modal for Adding Specialty */}
            {bIsAdding && (
                <InfoModal title={fnT('finishingTouches.specialties.addSpecialty')} onClose={() => fnSetIsAdding(false)}>
                    <div className="space-y-4">
                        {aAvailableSkills.length === 0 ? (
                            <div className="text-center p-4">
                                <ExclamationCircle />
                                <p className="text-red-400 mt-2">{fnT('finishingTouches.specialties.noSkillsAvailable')}</p>
                            </div>
                        ) : (
                            <>
                                <div>
                                    <label className="block text-sm font-medium text-gray-300 mb-1">
                                        {fnT('finishingTouches.specialties.selectSkill')}
                                    </label>
                                    <select 
                                        value={sNewSpecialtySkill}
                                        onChange={e => fnSetNewSpecialtySkill(e.target.value)}
                                        className="w-full bg-gray-800 border border-gray-600 rounded-md shadow-sm px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-red-500"
                                    >
                                        <option value="">{fnT('common.selectPlaceholder')}</option>
                                        {aAvailableSkills.map(s => (
                                            <option key={s} value={s}>{fnT(`skills.list.${s}`)} ({oCharacter.skills[s]})</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <Input 
                                        label={fnT('finishingTouches.specialties.enterSpecialty')}
                                        value={sNewSpecialtyName}
                                        onChange={e => fnSetNewSpecialtyName(e.target.value)}
                                        placeholder={sNewSpecialtySkill ? fnT(`skills.specialtyExamples.${sNewSpecialtySkill}`) : fnT('finishingTouches.specialties.enterSpecialty')}
                                    />
                                </div>
                                <div className="flex justify-end gap-2 pt-4">
                                    <Button variant="secondary" onClick={() => fnSetIsAdding(false)}>{fnT('buttons.cancel')}</Button>
                                    <Button disabled={!sNewSpecialtySkill || !sNewSpecialtyName} onClick={fnHandleAddSpecialty}>{fnT('buttons.confirm')}</Button>
                                </div>
                            </>
                        )}
                    </div>
                </InfoModal>
            )}
        </div>
    );
}

const StepFinishingTouches: React.FC<FinishingTouchesProps> = ({ character: oCharacter, baseCharacter: oBaseCharacter, updateCharacter: fnUpdateCharacter, onShowDiscipline: fnOnShowDiscipline, predatorTypes: aPredatorTypes }) => {
    const { t: fnT } = useI18n();
    const oClanDetails = fnGetClanDetails(fnT);
    const oDisciplineDetails = fnGetDisciplineDetails(fnT);

    const aClanDisciplines = useMemo(() => oCharacter.clan ? oClanDetails[oCharacter.clan].disciplines : [], [oCharacter.clan, oClanDetails]);
    const aDisciplinePool = useMemo(() => [2, 1], []);

    // Handle Discipline Changes via Allocator
    const fnHandleDisciplineChange = (sDiscipline: string, nValue: number) => {
        // We act on baseCharacter.disciplines (user allocated)
        const oCurrentDisciplines = { ...oBaseCharacter.disciplines };

        if (nValue === 0) {
            delete oCurrentDisciplines[sDiscipline];
        } else {
            oCurrentDisciplines[sDiscipline] = nValue;
        }
        fnUpdateCharacter('disciplines', oCurrentDisciplines);

        // Also cleanup discipline powers if we reduce dots below selection count
        const oCurrentPowers = { ...oBaseCharacter.disciplinePowers };
        if (nValue === 0) {
             delete oCurrentPowers[sDiscipline];
             fnUpdateCharacter('disciplinePowers', oCurrentPowers);
        }
    };

    const fnHandlePowerSelection = (sDiscipline: string, aPowerIds: string[]) => {
        fnUpdateCharacter('disciplinePowers', {
            ...oCharacter.disciplinePowers,
            [sDiscipline]: aPowerIds
        });
    };

    const oCurrentPredatorType = oCharacter.predatorType ? aPredatorTypes.find(p => p.name === oCharacter.predatorType) : null;

    return (
        <div className="space-y-8">
            <LoreQuote text={fnT('lore.finishing')} />
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Disciplines Selection */}
                <div>
                    <div className="flex justify-between items-center mb-2">
                        <h3 className="text-lg font-bold text-red-400">{fnT('finishingTouches.disciplines.title')}</h3>
                        <div className="flex gap-2">
                             {Object.values(oDisciplineDetails).map(oDisc => (
                                aClanDisciplines.includes(oDisc.name) && (
                                    <InfoIcon key={oDisc.name} onClick={() => fnOnShowDiscipline(oDisc)} className="text-red-500 hover:text-white" />
                                )
                            ))}
                        </div>
                    </div>
                    <p className="text-sm text-gray-400 mb-4">{fnT('finishingTouches.disciplines.subtitle')}</p>

                    {oCharacter.clan ? (
                        <PointAllocator 
                            items={aClanDisciplines} 
                            values={oCharacter.disciplines as Record<string, number>} // Display TOTAL dots (base + predator)
                            onChange={fnHandleDisciplineChange}
                            pool={aDisciplinePool}
                            baseValue={0}
                            customRenderer={(sItem) => (
                                <span className="flex items-center gap-2">
                                    {sItem}
                                </span>
                            )}
                            renderAfterItem={(sItem, nValue) => {
                                return (
                                    <DisciplinePowerSelector 
                                        disciplineKey={sItem}
                                        dots={nValue} 
                                        selectedPowerIds={oCharacter.disciplinePowers[sItem] || []}
                                        onSelectPowers={(aIds) => fnHandlePowerSelection(sItem, aIds)}
                                        disciplineDetails={oDisciplineDetails[sItem]}
                                    />
                                );
                            }}
                        />
                    ) : (
                        <p className="text-gray-500 italic border border-dashed border-gray-700 p-4 rounded text-center">{fnT('common.noClanSelected')}</p>
                    )}

                    {/* Handle Non-Clan Disciplines (e.g. from Predator Type) that aren't in the allocator */}
                    {(Object.entries(oCharacter.disciplines) as [string, number][]).map(([sDisc, nDots]) => {
                         if (aClanDisciplines.includes(sDisc)) return null; // Handled above
                         if (nDots <= 0) return null;
                         const oDetails = oDisciplineDetails[sDisc];
                         if (!oDetails) return null;

                         return (
                             <div key={sDisc} className="mt-4 p-3 bg-gray-800 rounded border border-gray-700">
                                 <div className="flex justify-between mb-2">
                                     <span className="font-bold text-gray-200">{sDisc}</span>
                                     <div className="flex items-center gap-2">
                                        <span className="text-red-400 font-bold">{nDots}</span>
                                        <div className="flex space-x-0.5">
                                            {[...Array(5)].map((_, nI) => (
                                                <div key={nI} className={`w-1.5 h-1.5 rounded-full ${nDots > nI ? 'bg-red-500' : 'bg-gray-800'}`}></div>
                                            ))}
                                        </div>
                                     </div>
                                 </div>
                                 <DisciplinePowerSelector 
                                    disciplineKey={sDisc}
                                    dots={nDots}
                                    selectedPowerIds={oCharacter.disciplinePowers[sDisc] || []}
                                    onSelectPowers={(aIds) => fnHandlePowerSelection(sDisc, aIds)}
                                    disciplineDetails={oDetails}
                                 />
                             </div>
                         )
                    })}
                </div>

                {/* Predator Type Selection */}
                <div>
                     <h3 className="text-lg font-bold text-red-400 mb-2">{fnT('finishingTouches.predatorType.title')}</h3>
                     <div className="space-y-2 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                        {aPredatorTypes.map(oPt => {
                            const bIsSelected = oCharacter.predatorType === oPt.name;
                            return (
                            <div key={oPt.name} className={`p-3 rounded-md border cursor-pointer transition-all duration-200 ${bIsSelected ? 'border-red-500 bg-red-900 bg-opacity-30' : 'border-gray-700 hover:border-gray-600'}`} onClick={() => fnUpdateCharacter('predatorType', oPt.name)}>
                                <div className="flex justify-between items-start">
                                    <p className="font-bold text-gray-200">{oPt.name}</p>
                                    {bIsSelected && <div className="h-2 w-2 rounded-full bg-red-500 mt-1.5"></div>}
                                </div>
                                <p className="text-sm text-gray-400 mt-1">{oPt.description}</p>

                                {bIsSelected && (
                                    <div className="mt-3 pt-3 border-t border-red-900/50 text-xs space-y-2 animate-fadeIn">
                                        {oPt.disciplineAdd && (
                                            <div>
                                                <strong className="text-red-400">{fnT('finishingTouches.disciplines.title')}:</strong>
                                                <span className="text-gray-300 ml-1">+{oPt.disciplineAdd.dots} {oPt.disciplineAdd.discipline}</span>
                                            </div>
                                        )}
                                        {oPt.advantages.length > 0 && (
                                            <div>
                                                <strong className="text-red-400">{fnT('finishingTouches.advantages.title')}:</strong>
                                                <ul className="list-disc list-inside text-gray-300 ml-1">
                                                    {oPt.advantages.map((oAdv, nI) => (
                                                        <li key={nI}>{oAdv.name} ({oAdv.cost})</li>
                                                    ))}
                                                </ul>
                                            </div>
                                        )}
                                        {oPt.flaws.length > 0 && (
                                            <div>
                                                <strong className="text-red-400">{fnT('finishingTouches.flaws.title')}:</strong>
                                                <ul className="list-disc list-inside text-gray-300 ml-1">
                                                    {oPt.flaws.map((oFlaw, nI) => (
                                                        <li key={nI}>{oFlaw.name} ({oFlaw.cost})</li>
                                                    ))}
                                                </ul>
                                            </div>
                                        )}
                                         {(oPt.specialties.length > 0 || (oPt.specialtyOptions && oPt.specialtyOptions.length > 0)) && (
                                            <div>
                                                <strong className="text-red-400">{fnT('characterSheet.specialties')}:</strong>
                                                <ul className="list-disc list-inside text-gray-300 ml-1">
                                                    {oPt.specialties.map((oSpec, nI) => (
                                                        <li key={nI}>{fnT(`skills.list.${oSpec.skill}`)} ({oSpec.name})</li>
                                                    ))}
                                                    {oPt.specialtyOptions && oPt.specialtyOptions.length > 0 && (
                                                        <li className="italic text-gray-400">{fnT('finishingTouches.specialties.choice')}</li>
                                                    )}
                                                </ul>
                                            </div>
                                        )}
                                        {oPt.humanityModifier !== 0 && (
                                            <div>
                                                 <strong className="text-red-400">{fnT('characterSheet.humanity')}:</strong>
                                                 <span className="text-gray-300 ml-1">{oPt.humanityModifier > 0 ? '+' : ''}{oPt.humanityModifier}</span>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        )})}
                     </div>
                </div>

                <SpecialtySelector character={oCharacter} updateCharacter={fnUpdateCharacter} predatorType={oCurrentPredatorType} />

                <AdvantageFlawSelector baseCharacter={oBaseCharacter} updateCharacter={fnUpdateCharacter} predatorType={oCurrentPredatorType}/>

                 <div className="md:col-span-2">
                     <TextArea label={fnT('finishingTouches.touchstones')} placeholder={fnT('finishingTouches.touchstonesPlaceholder')} value={oCharacter.touchstones} onChange={e => fnUpdateCharacter('touchstones', e.target.value)} />
                </div>
            </div>
        </div>
    );
}

