                                </div>
                                <div className="mt-4 border-t border-gray-700 pt-2">
                                    {oCharacter.flaws.map((flaw, i) => (
                                        <div key={i} className="flex justify-between text-sm text-gray-300">
                                            <span>{flaw.name}</span>
                                            <button onClick={() => fnUpdateCharacter('flaws', oCharacter.flaws.filter((_, idx) => idx !== i))} className="text-red-500">x</button>
                                        </div>
                                    ))}
                                </div>
                            </GothicFrame>
                        </div>
                    </div>
                );
            case 6: // Sheet
                return <CharacterSheet character={oCharacter} onUpdateHunger={(h) => fnUpdateCharacter('hunger', h)} />;
            default:
                return null;
        }
    };

    return (
        <div className="min-h-screen bg-gray-900 text-white font-sans selection:bg-red-900 selection:text-white flex flex-col">
            <header className="bg-black border-b-2 border-red-900 p-4 sticky top-0 z-50 shadow-2xl">
                <div className="max-w-7xl mx-auto flex justify-between items-center">
                    <div className="flex items-center gap-3">
                         <div className="text-red-600">
                             <RoseIcon className="w-10 h-10" />
                         </div>
                        <div>
                            <h1 className="text-2xl font-cinzel font-bold text-red-600 tracking-widest">{fnT('app.title')}</h1>
                            <p className="text-xs text-gray-500 hidden md:block">{fnT('app.subtitle')}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <Button variant="secondary" onClick={() => { fnSetStorageMode('save'); fnSetShowStorage(true); }} title={fnT('buttons.save')}>
                            <FloppyDiskIcon />
                        </Button>
                        <Button variant="secondary" onClick={() => { fnSetStorageMode('load'); fnSetShowStorage(true); }} title={fnT('buttons.load')}>
                            <FolderOpenIcon />
                        </Button>
                        <Button variant="secondary" onClick={() => fnUpdateCharacter('name', '') /* Reset logic trigger */} title={fnT('buttons.reset')}>
                            <ResetIcon />
                        </Button>
                         <div className="ml-2 border-l border-gray-700 pl-2 flex gap-2">
                            <Button variant="secondary" onClick={fnExportJSON} className="text-xs hidden md:block">{fnT('buttons.export')}</Button>
                            <label className="cursor-pointer bg-gray-600 hover:bg-gray-500 px-3 py-1 rounded text-xs font-bold flex items-center hidden md:flex">
                                {fnT('buttons.import')}
                                <input type="file" className="hidden" accept=".json" onChange={fnImportJSON} />
                            </label>
                        </div>
                    </div>
                </div>
            </header>

            <main className="flex-grow p-4 md:p-8 max-w-6xl mx-auto w-full">
                <StepIndicator currentStep={nStep} totalSteps={6} steps={aSteps} />

                {nStep < 6 && <CharacterSummary character={oCharacter} />}

                <div className="mt-8 animate-fadeIn">
                    {renderStepContent()}
                </div>
            </main>

            <footer className="bg-black border-t border-gray-800 p-6 sticky bottom-0 z-40">
                <div className="max-w-6xl mx-auto flex justify-between items-center">
                    <Button 
                        onClick={() => fnSetStep(prev => Math.max(1, prev - 1))}
                        disabled={nStep === 1}
                        variant="secondary"
                    >
                        {fnT('buttons.back')}
                    </Button>

                    {nStep < 6 ? (
                        <div className="flex gap-4">
                            <Button variant="secondary" onClick={() => fnSetStep(6)}>{fnT('buttons.jumpToSheet')}</Button>
                            <Button onClick={() => fnSetStep(prev => Math.min(6, prev + 1))}>
                                {fnT('buttons.next')}
                            </Button>
                        </div>
                    ) : (
                        <Button variant="secondary" onClick={() => window.print()}>{fnT('buttons.print') || 'Print'}</Button>
                    )}
                </div>
            </footer>

            {bShowStorage && (
                <StorageModal 
                    mode={sStorageMode}
                    onClose={() => fnSetShowStorage(false)}
                    currentName={oCharacter.name}
                    onSave={fnSaveCharacter}
                    onLoad={fnLoadCharacter}
                    onDelete={fnDeleteCharacter}
                />
            )}
        </div>
    );
};

