                        <Button variant="secondary" onClick={() => { fnSetStorageMode('load'); fnSetShowStorage(true); }} title={fnT('buttons.load')}>
                            <FolderOpenIcon />
                        </Button>
                        <Button variant="secondary" onClick={fnResetCharacter} title={fnT('buttons.reset')}>
                            <ResetIcon />
