export const fnGenerateName = (): string => {
    const sTitle = aTitles[Math.floor(Math.random() * aTitles.length)];
    const sFirst = aFirstNames[Math.floor(Math.random() * aFirstNames.length)];
    const sLast = aLastNames[Math.floor(Math.random() * aLastNames.length)];

    return `${sTitle ? sTitle + " " : ""}${sFirst} ${sLast}`;
};

export const fnGenerateConcept = (): string => {
    const nTemplate = Math.random();
    const sAdj = aAdjectives[Math.floor(Math.random() * aAdjectives.length)];
    const sRole = aRoles[Math.floor(Math.random() * aRoles.length)];
    const sContext = aContexts[Math.floor(Math.random() * aContexts.length)];

    if (nTemplate < 0.4) {
        // Template 1: Adjective Role (e.g. "Corrupt Cop")
        return `${sAdj} ${sRole}`;
    } else if (nTemplate < 0.7) {
        // Template 2: Role Context (e.g. "Doctor seeking redemption")
        return `${sRole} ${sContext}`;
    } else {
        // Template 3: Complex (e.g. "Disgraced Politician with a dark secret")
        return `${sAdj} ${sRole} ${sContext}`;
    }
};

export const fnGenerateIdentity = () => {
    return {
        name: fnGenerateName(),
        sire: fnGenerateName(),
        concept: fnGenerateConcept()
    };
};

