export const fnGenerateName = (sLocale: string = 'en'): string => {
    // Default to 'en' if locale not found
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;

    const sTitle = oData.titles[Math.floor(Math.random() * oData.titles.length)];
    const sFirst = oData.firstNames[Math.floor(Math.random() * oData.firstNames.length)];
    const sLast = oData.lastNames[Math.floor(Math.random() * oData.lastNames.length)];

    return `${sTitle ? sTitle + " " : ""}${sFirst} ${sLast}`;
};

export const fnGenerateConcept = (sLocale: string = 'en'): string => {
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;
    const nTemplate = Math.random();

    const sAdj = oData.adjectives[Math.floor(Math.random() * oData.adjectives.length)];
    const sRole = oData.roles[Math.floor(Math.random() * oData.roles.length)];
    const sContext = oData.contexts[Math.floor(Math.random() * oData.contexts.length)];

    // Adjust word order for Portuguese (Noun + Adjective) vs English (Adjective + Noun)
    if (sLocale === 'pt') {
        if (nTemplate < 0.4) {
            // Template 1: Role Adjective (e.g. "Policial Corrupto")
            return `${sRole} ${sAdj}`;
        } else if (nTemplate < 0.7) {
            // Template 2: Role Context (e.g. "Médico buscando redenção")
            return `${sRole} ${sContext}`;
        } else {
            // Template 3: Complex (e.g. "Político Desonrado com um segredo")
            return `${sRole} ${sAdj} ${sContext}`;
        }
    } else {
        if (nTemplate < 0.4) {
            // Template 1: Adjective Role (e.g. "Corrupt Cop")
            return `${sAdj} ${sRole}`;
        } else if (nTemplate < 0.7) {
            // Template 2: Role Context (e.g. "Doctor seeking redemption")
            return `${sRole} ${sContext}`;
        } else {
            // Template 3: Complex (e.g. "Disgraced Politician with a dark secret")
            return `${sAdj} ${sRole} ${sContext}`;
        }
    }
};

export const fnGenerateIdentity = (sLocale: string = 'en') => {
    return {
        name: fnGenerateName(sLocale),
        sire: fnGenerateName(sLocale),
        concept: fnGenerateConcept(sLocale)
    };
};

