const getRandomGender = (): Gender => Math.random() > 0.5 ? 'male' : 'female';

export const fnGenerateName = (sLocale: string = 'en', gender?: Gender): string => {
    // If gender not provided, pick one randomly
    const selectedGender = gender || getRandomGender();
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;

    // Chance to have a title (15%)
    const bHasTitle = Math.random() < 0.15;

    let sTitle = "";
    if (bHasTitle) {
        const titles = oData.titles[selectedGender];
        sTitle = titles[Math.floor(Math.random() * titles.length)];
    }

    const names = oData.firstNames[selectedGender];
    const sFirst = names[Math.floor(Math.random() * names.length)];
    const sLast = oData.lastNames[Math.floor(Math.random() * oData.lastNames.length)];

    return `${sTitle ? sTitle + " " : ""}${sFirst} ${sLast}`;
};

export const fnGenerateConcept = (sLocale: string = 'en', gender?: Gender): string => {
    const selectedGender = gender || getRandomGender();
    const genderIndex = selectedGender === 'male' ? 0 : 1; // 0 for Male, 1 for Female tuple index
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;
    const nTemplate = Math.random();

    // Select components using the gender index
    const sAdj = oData.adjectives[Math.floor(Math.random() * oData.adjectives.length)][genderIndex];
    const sRole = oData.roles[Math.floor(Math.random() * oData.roles.length)][genderIndex];
    const sContext = oData.contexts[Math.floor(Math.random() * oData.contexts.length)][genderIndex];

    // Adjust word order for Portuguese (Noun + Adjective) vs English (Adjective + Noun)
    if (sLocale === 'pt') {
        if (nTemplate < 0.4) {
            // Template 1: Role Adjective (e.g. "Policial Corrupto" / "Policial Corrupta")
            return `${sRole} ${sAdj}`;
        } else if (nTemplate < 0.7) {
            // Template 2: Role Context (e.g. "Médico buscando redenção" / "Médica buscando redenção")
            return `${sRole} ${sContext}`;
        } else {
            // Template 3: Complex (e.g. "Político Desonrado com um segredo" / "Política Desonrada...")
            return `${sRole} ${sAdj} ${sContext}`;
        }
    } else {
        if (nTemplate < 0.4) {
            return `${sAdj} ${sRole}`;
        } else if (nTemplate < 0.7) {
            return `${sRole} ${sContext}`;
        } else {
            return `${sAdj} ${sRole} ${sContext}`;
        }
    }
};

export const fnGenerateIdentity = (sLocale: string = 'en') => {
    // Generate gender for the main character to ensure agreement between Name and Concept
    const charGender = getRandomGender();

    // Generate a separate gender for the Sire
    const sireGender = getRandomGender();

    return {
        name: fnGenerateName(sLocale, charGender),
        sire: fnGenerateName(sLocale, sireGender),
        concept: fnGenerateConcept(sLocale, charGender)
    };
};

