    titles: { male: string[], female: string[] };
    firstNames: { male: string[], female: string[] };
    lastNames: string[];
    // Concepts are stored as tuples [MaleVariant, FemaleVariant]
    // If the word is neutral (e.g. "Hacker"), both entries are the same.
    adjectives: [string, string][]; 
    roles: [string, string][];
    contexts: [string, string][];
}

