const getRandomGender = (): Gender => Math.random() > 0.5 ? 'male' : 'female';

export const fnGenerateName = (sLocale: string = 'en', gender?: Gender): string => {
    // If gender not provided, pick one randomly
    const selectedGender = gender || getRandomGender();
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;

    // Chance to have a title (15%)
    const bHasTitle = Math.random() < 0.15;

    let sTitle = "";
    if (bHasTitle) {
        const titles = oData.titles[selectedGender];
        sTitle = titles[Math.floor(Math.random() * titles.length)];
    }

    const names = oData.firstNames[selectedGender];
    const sFirst = names[Math.floor(Math.random() * names.length)];
    const sLast = oData.lastNames[Math.floor(Math.random() * oData.lastNames.length)];

    return `${sTitle ? sTitle + " " : ""}${sFirst} ${sLast}`;
};

export const fnGenerateConcept = (sLocale: string = 'en', gender?: Gender) => {
    const selectedGender = gender || getRandomGender();
    const genderIndex = selectedGender === 'male' ? 0 : 1; // 0 for Male, 1 for Female tuple index
    const oData = DATA[sLocale as keyof typeof DATA] || DATA.en;
    const nTemplate = Math.random();

    // Select components using the gender index
    const adjectivePair = oData.adjectives[Math.floor(Math.random() * oData.adjectives.length)];
    const rolePair = oData.roles[Math.floor(Math.random() * oData.roles.length)];
    const contextPair = oData.contexts[Math.floor(Math.random() * oData.contexts.length)];

    const sAdj = adjectivePair[genderIndex];
    const sRole = rolePair[genderIndex];
    const sContext = contextPair[genderIndex];

    // Standard English Role for logic processing (detected via index match or similar, but simpler to return key if we had it. 
    // Here we return the tuple index 0 of English data if possible, but let's just return the localized string and handle logic by index matching if needed, 
    // OR better: Return the "English Male" version as a unique Key for logic).

    // Find index of role in current locale to map back to English key if needed, 
    // or just assume we build a lookup map in the randomizer.
    // Let's return the "English Male" version of the role as a `roleKey` for the logic engine.

    let roleKey = rolePair[0]; // Default to current locale male

    // Reverse lookup to find the English key if we are in PT
    if (sLocale !== 'en') {
        // Find index in PT list
        const idx = DATA.pt.roles.findIndex(r => r[0] === rolePair[0]);
        if (idx !== -1) {
            roleKey = DATA.en.roles[idx][0];
        }
    } else {
        roleKey = rolePair[0];
    }

    let conceptString = "";

    // Adjust word order for Portuguese (Noun + Adjective) vs English (Adjective + Noun)
    if (sLocale === 'pt') {
        if (nTemplate < 0.4) {
            conceptString = `${sRole} ${sAdj}`;
        } else if (nTemplate < 0.7) {
            conceptString = `${sRole} ${sContext}`;
        } else {
            conceptString = `${sRole} ${sAdj} ${sContext}`;
        }
    } else {
        if (nTemplate < 0.4) {
            conceptString = `${sAdj} ${sRole}`;
        } else if (nTemplate < 0.7) {
            conceptString = `${sRole} ${sContext}`;
        } else {
            conceptString = `${sAdj} ${sRole} ${sContext}`;
        }
    }

    return {
        concept: conceptString,
        roleKey: roleKey // Returns "Detective", "Hacker", etc (English Male version) for logic
    };
};

export const fnGenerateIdentity = (sLocale: string = 'en') => {
    // Generate gender for the main character to ensure agreement between Name and Concept
    const charGender = getRandomGender();

    // Generate a separate gender for the Sire
    const sireGender = getRandomGender();

    const conceptData = fnGenerateConcept(sLocale, charGender);

    return {
        name: fnGenerateName(sLocale, charGender),
        sire: fnGenerateName(sLocale, sireGender),
        concept: conceptData.concept,
        roleKey: conceptData.roleKey
    };
};

