type XPLevel = 'fledgling' | 'neonate' | 'ancilla';

// Archetypes define priorities for attributes and skills
const ARCHETYPES = {
    PHYSICAL: {
        attributes: [Attribute.Strength, Attribute.Dexterity, Attribute.Stamina],
