// Helper to shuffle array
const shuffle = <T>(array: T[]): T[] => {
    return array.map(value => ({ value, sort: Math.random() }))
        .sort((a, b) => a.sort - b.sort)
        .map(({ value }) => value);
};

export const fnCreateRandomCharacter = (sLocale: string, sLevel: XPLevel, fnT: (k: string) => string): Character => {
    const identity = fnGenerateIdentity(sLocale);
    const sRoleKey = identity.roleKey;
    const archetypeKey = ROLE_MAP[sRoleKey] || (Object.keys(ARCHETYPES)[Math.floor(Math.random() * 3)] as keyof typeof ARCHETYPES);
    const archetype = ARCHETYPES[archetypeKey];

    // 1. Attributes: 4, 3, 3, 3, 2, 2, 2, 2, 1
    const attributes = { ...oInitialCharacter.attributes };
    const attrPool = [4, 3, 3, 3, 2, 2, 2, 2, 1];

    // Identify priority attributes based on Archetype
    const priorityAttrs = shuffle(archetype.attributes);
    const otherAttrs = shuffle(aAttributeList.filter(a => !archetype.attributes.includes(a)));
    const allAttrsOrdered = [...priorityAttrs, ...otherAttrs];

    // Assign values
    allAttrsOrdered.forEach((attr, idx) => {
        attributes[attr] = attrPool[idx];
    });

    // 2. Skills: Specialist (4, 3,3, 2,2,2, 1,1,1) - adjusted for V5 standard creation limits usually sum to 22+
    // Specialist: 1@4, 3@3, 3@2, 3@1 = 4+9+6+3 = 22 dots.
    const skills = { ...oInitialCharacter.skills };
    const skillPool = [4, 3, 3, 3, 2, 2, 2, 1, 1, 1]; // Top 10 skills get dots

    const prioritySkills = shuffle(archetype.skills);
    const otherSkills = shuffle(aSkillList.filter(s => !archetype.skills.includes(s)));
    const allSkillsOrdered = [...prioritySkills, ...otherSkills];

    // Assign dots to top 10 skills
    for (let i = 0; i < skillPool.length; i++) {
        skills[allSkillsOrdered[i]] = skillPool[i];
    }

    // 3. Clan
    const clanList = Object.values(Clan);
    const selectedClan = clanList[Math.floor(Math.random() * clanList.length)];
    const clanDetails = fnGetClanDetails(fnT)[selectedClan];

    // 4. Disciplines (2 dots in one, 1 in another)
    const disciplines: Record<string, number> = {};
    const disciplinePowers: Record<string, string[]> = {};
    const clanDiscNames = shuffle([...clanDetails.disciplines]);

    if (clanDiscNames.length > 0) {
        // Primary Clan Disc (2 dots)
        const d1 = clanDiscNames[0];
        disciplines[d1] = 2;
        // Secondary Clan Disc (1 dot)
        if (clanDiscNames.length > 1) {
            const d2 = clanDiscNames[1];
            disciplines[d2] = 1;
        } else {
            // Caitiff might have empty list or specific logic, but assuming standard list for now
            // If Caitiff, pick random disciplines
             if (selectedClan === Clan.Caitiff) {
                 const allDiscs = Object.keys(fnGetDisciplineDetails(fnT));
                 const shuffled = shuffle(allDiscs);
                 disciplines[shuffled[0]] = 2;
                 disciplines[shuffled[1]] = 1;
             }
        }
    }

    // Assign Powers Logic (Simple: Pick level 1s and 2s)
    const allDiscDetails = fnGetDisciplineDetails(fnT);
    Object.keys(disciplines).forEach(dKey => {
        const dots = disciplines[dKey];
        const details = allDiscDetails[dKey];
        if (details) {
            const powers = details.powers.filter(p => p.level <= dots);
            // Naive selection: just take the first ones that fit levels
            // A better logic would be: for level 1, pick 1. For level 2, pick 1 level 1 or 2.
            // Simplified: Filter by level, pick `dots` amount unique powers, ensuring level reqs.
            const selected: string[] = [];
            // Pick Level 1
            const l1s = details.powers.filter(p => p.level === 1);
            if (l1s.length > 0) selected.push(l1s[Math.floor(Math.random() * l1s.length)].id);

            if (dots >= 2) {
                // Pick Level 2 or another Level 1
                const l2s = details.powers.filter(p => p.level <= 2 && !selected.includes(p.id));
                if (l2s.length > 0) selected.push(l2s[Math.floor(Math.random() * l2s.length)].id);
            }
            disciplinePowers[dKey] = selected;
        }
    });

    // 5. Predator Type
    const predatorTypes = fnGetPredatorTypes(fnT);
    const selectedPredator = predatorTypes[Math.floor(Math.random() * predatorTypes.length)];
    const predatorName = selectedPredator.name;

    // Apply Predator Bonuses
    // - Add Discipline dot
    if (selectedPredator.disciplineAdd) {
        const dName = selectedPredator.disciplineAdd.discipline;
        const currentDots = disciplines[dName] || 0;
        disciplines[dName] = currentDots + selectedPredator.disciplineAdd.dots;

        // Add power for this new dot
        const details = allDiscDetails[dName];
        if (details) {
            const newDots = disciplines[dName];
            const existing = disciplinePowers[dName] || [];
            const available = details.powers.filter(p => p.level <= newDots && !existing.includes(p.id));
            if (available.length > 0) {
                existing.push(available[Math.floor(Math.random() * available.length)].id);
                disciplinePowers[dName] = existing;
            }
        }
    }

    // - Add Specialties (Pick 1 from options if available)
    const specialties = [...selectedPredator.specialties];
    if (selectedPredator.specialtyOptions && selectedPredator.specialtyOptions.length > 0) {
        specialties.push(selectedPredator.specialtyOptions[Math.floor(Math.random() * selectedPredator.specialtyOptions.length)]);
    }

    // - Advantages/Flaws
    let advantages = [...selectedPredator.advantages];
    let flaws = [...selectedPredator.flaws];

    // 6. XP Level Adjustments (Simplified for Randomizer)
    let generation = 12;
    let bloodPotency = 1;
    let humanity = 7 + selectedPredator.humanityModifier;

    if (sLevel === 'neonate') { // 15 XP
        generation = Math.floor(Math.random() * (12 - 10 + 1)) + 10; // 10-12
        // Spend approx 15 XP: e.g. +1 Attribute dot (primary) or +2 Skill dots
        const bestAttr = priorityAttrs[0];
        attributes[bestAttr] = Math.min(5, attributes[bestAttr] + 1); // Bump best attr
    } else if (sLevel === 'ancilla') { // 35 XP
        generation = Math.floor(Math.random() * (11 - 9 + 1)) + 9; // 9-11
        bloodPotency = 2;
        // Spend approx 35 XP:
        // Bump best attribute
        const bestAttr = priorityAttrs[0];
        attributes[bestAttr] = Math.min(5, attributes[bestAttr] + 1); 
        // Bump best skill
        const bestSkill = prioritySkills[0];
        skills[bestSkill] = Math.min(5, skills[bestSkill] + 1);
        // Add 1 dot to primary discipline
        if (clanDiscNames.length > 0) {
            const d1 = clanDiscNames[0];
            disciplines[d1] = Math.min(5, (disciplines[d1] || 0) + 1);
             // Add power
            const details = allDiscDetails[d1];
            if (details) {
                const existing = disciplinePowers[d1] || [];
                const available = details.powers.filter(p => p.level <= disciplines[d1] && !existing.includes(p.id));
                if (available.length > 0) {
                    existing.push(available[Math.floor(Math.random() * available.length)].id);
                    disciplinePowers[d1] = existing;
                }
            }
        }
        // Add generic advantages to simulate history
        advantages.push({ name: fnT('advantages.resources.name'), description: fnT('advantages.resources.description'), cost: 2, type: 'advantage', levels: [2] });
        flaws.push({ name: fnT('flaws.enemy.name'), description: fnT('flaws.enemy.description'), cost: 1, type: 'flaw', levels: [1] });
    }

    // Derived Stats
    const health = attributes[Attribute.Stamina] + 3;
    const willpower = attributes[Attribute.Composure] + attributes[Attribute.Resolve];

    return {
        ...oInitialCharacter,
        name: identity.name,
        concept: identity.concept,
        sire: identity.sire,
        clan: selectedClan,
        generation,
        bloodPotency,
        humanity,
        attributes,
        skills,
        disciplines,
        disciplinePowers,
        predatorType: predatorName,
        specialties,
        advantages,
        flaws,
        health,
        willpower,
        hunger: 1
    };
};

