                                <span className="font-bold text-white">Random Neonate</span>
                                <span className="text-xs text-gray-500">15 XP • 12th Gen</span>
                            </Button>
                            <Button 
                                variant="secondary" 
                                className="py-3 text-sm flex flex-col items-center gap-1 hover:border-gray-400 border border-gray-700 bg-gray-800"
