import { Character, Clan, Attribute, Skill, DisciplineDetail, PredatorTypeDetail, AdvantageFlaw } from '../types';
import { oInitialCharacter, fnGetClanDetails, fnGetPredatorTypes, fnGetDisciplineDetails, aAttributeList, aSkillList } from '../constants';
import { fnGenerateIdentity } from './generators';

type XPLevel = 'fledgling' | 'neonate' | 'ancilla';

// Archetypes define priorities for attributes and skills
const ARCHETYPES = {
    PHYSICAL: {
        attributes: [Attribute.Strength, Attribute.Dexterity, Attribute.Stamina],
        skills: [Skill.Brawl, Skill.Athletics, Skill.Melee, Skill.Larceny, Skill.Survival, Skill.Drive]
    },
    SOCIAL: {
        attributes: [Attribute.Charisma, Attribute.Manipulation, Attribute.Composure],
        skills: [Skill.Persuasion, Skill.Subterfuge, Skill.Intimidation, Skill.Leadership, Skill.Etiquette, Skill.Streetwise, Skill.Performance]
    },
    MENTAL: {
        attributes: [Attribute.Intelligence, Attribute.Wits, Attribute.Resolve],
        skills: [Skill.Investigation, Skill.Academics, Skill.Science, Skill.Technology, Skill.Finance, Skill.Medicine, Skill.Occult, Skill.Politics]
    }
};

// Map Role Keys (from generators.ts en list) to Archetypes
const ROLE_MAP: Record<string, keyof typeof ARCHETYPES> = {
    "Detective": "MENTAL", "Surgeon": "MENTAL", "Hacker": "MENTAL", "Scientist": "MENTAL", 
    "Professor": "MENTAL", "Lawyer": "MENTAL", "Judge": "MENTAL", "Historian": "MENTAL", 
    "Librarian": "MENTAL", "Coder": "MENTAL", "Writer": "MENTAL", "Journalist": "MENTAL", 
    "Paramedic": "MENTAL", "Coroner": "MENTAL",

    "Soldier": "PHYSICAL", "Mercenary": "PHYSICAL", "Bouncer": "PHYSICAL", "Thief": "PHYSICAL", 
    "Assassin": "PHYSICAL", "Criminal": "PHYSICAL", "Cleaner": "PHYSICAL", "Driver": "PHYSICAL", 
    "Pilot": "PHYSICAL", "Vigilante": "PHYSICAL", "Chef": "PHYSICAL", "Bartender": "PHYSICAL",

    "Influencer": "SOCIAL", "Drug Dealer": "SOCIAL", "CEO": "SOCIAL", "Artist": "SOCIAL", 
    "Musician": "SOCIAL", "Student": "SOCIAL", "Politician": "SOCIAL", "Priest": "SOCIAL", 
    "Occultist": "MENTAL", // Arguable
    "Model": "SOCIAL", "Actor": "SOCIAL", "Director": "SOCIAL", "Activist": "SOCIAL",
    "Anarchist": "SOCIAL", "Loyalist": "SOCIAL", "Autarkis": "SOCIAL", "Sire": "SOCIAL", 
    "Childe": "SOCIAL", "Ghoul-Master": "SOCIAL", "Blood Doll": "SOCIAL", "Fixer": "SOCIAL", 
    "Club Owner": "SOCIAL", "Socialite": "SOCIAL", "Heir": "SOCIAL"
};

// Helper to shuffle array
const shuffle = <T>(array: T[]): T[] => {
    return array.map(value => ({ value, sort: Math.random() }))
        .sort((a, b) => a.sort - b.sort)
        .map(({ value }) => value);
};

export const fnCreateRandomCharacter = (sLocale: string, sLevel: XPLevel, fnT: (k: string) => string): Character => {
    const identity = fnGenerateIdentity(sLocale);
    const sRoleKey = identity.roleKey;
    const archetypeKey = ROLE_MAP[sRoleKey] || (Object.keys(ARCHETYPES)[Math.floor(Math.random() * 3)] as keyof typeof ARCHETYPES);
    const archetype = ARCHETYPES[archetypeKey];

    // 1. Attributes: 4, 3, 3, 3, 2, 2, 2, 2, 1
    const attributes = { ...oInitialCharacter.attributes };
    const attrPool = [4, 3, 3, 3, 2, 2, 2, 2, 1];

    // Identify priority attributes based on Archetype
    const priorityAttrs = shuffle(archetype.attributes);
    const otherAttrs = shuffle(aAttributeList.filter(a => !archetype.attributes.includes(a)));
    const allAttrsOrdered = [...priorityAttrs, ...otherAttrs];

    // Assign values
    allAttrsOrdered.forEach((attr, idx) => {
        attributes[attr] = attrPool[idx];
    });

    // 2. Skills: Specialist (4, 3,3, 2,2,2, 1,1,1) - adjusted for V5 standard creation limits usually sum to 22+
    // Specialist: 1@4, 3@3, 3@2, 3@1 = 4+9+6+3 = 22 dots.
    const skills = { ...oInitialCharacter.skills };
    const skillPool = [4, 3, 3, 3, 2, 2, 2, 1, 1, 1]; // Top 10 skills get dots

    const prioritySkills = shuffle(archetype.skills);
    const otherSkills = shuffle(aSkillList.filter(s => !archetype.skills.includes(s)));
    const allSkillsOrdered = [...prioritySkills, ...otherSkills];

    // Assign dots to top 10 skills
    for (let i = 0; i < skillPool.length; i++) {
        skills[allSkillsOrdered[i]] = skillPool[i];
    }

    // 3. Clan
    const clanList = Object.values(Clan);
    const selectedClan = clanList[Math.floor(Math.random() * clanList.length)];
    const clanDetails = fnGetClanDetails(fnT)[selectedClan];

    // 4. Disciplines (2 dots in one, 1 in another)
    const disciplines: Record<string, number> = {};
    const disciplinePowers: Record<string, string[]> = {};
    const clanDiscNames = shuffle([...clanDetails.disciplines]);

    if (clanDiscNames.length > 0) {
        // Primary Clan Disc (2 dots)
        const d1 = clanDiscNames[0];
        disciplines[d1] = 2;
        // Secondary Clan Disc (1 dot)
        if (clanDiscNames.length > 1) {
            const d2 = clanDiscNames[1];
            disciplines[d2] = 1;
        } else {
            // Caitiff might have empty list or specific logic, but assuming standard list for now
            // If Caitiff, pick random disciplines
             if (selectedClan === Clan.Caitiff) {
                 const allDiscs = Object.keys(fnGetDisciplineDetails(fnT));
                 const shuffled = shuffle(allDiscs);
                 disciplines[shuffled[0]] = 2;
                 disciplines[shuffled[1]] = 1;
             }
        }
    }

    // Assign Powers Logic (Simple: Pick level 1s and 2s)
    const allDiscDetails = fnGetDisciplineDetails(fnT);
    Object.keys(disciplines).forEach(dKey => {
        const dots = disciplines[dKey];
        const details = allDiscDetails[dKey];
        if (details) {
            const powers = details.powers.filter(p => p.level <= dots);
            const selected: string[] = [];
            // Pick Level 1
            const l1s = details.powers.filter(p => p.level === 1);
            if (l1s.length > 0) selected.push(l1s[Math.floor(Math.random() * l1s.length)].id);

            if (dots >= 2) {
                // Pick Level 2 or another Level 1
                const l2s = details.powers.filter(p => p.level <= 2 && !selected.includes(p.id));
                if (l2s.length > 0) selected.push(l2s[Math.floor(Math.random() * l2s.length)].id);
            }
            disciplinePowers[dKey] = selected;
        }
    });

    // 5. Predator Type
    const predatorTypes = fnGetPredatorTypes(fnT);
    const selectedPredator = predatorTypes[Math.floor(Math.random() * predatorTypes.length)];
    const predatorName = selectedPredator.name;

    // Apply Predator Bonuses
    if (selectedPredator.disciplineAdd) {
        const dName = selectedPredator.disciplineAdd.discipline;
        const currentDots = disciplines[dName] || 0;
        disciplines[dName] = currentDots + selectedPredator.disciplineAdd.dots;

        const details = allDiscDetails[dName];
        if (details) {
            const newDots = disciplines[dName];
            const existing = disciplinePowers[dName] || [];
            const available = details.powers.filter(p => p.level <= newDots && !existing.includes(p.id));
            if (available.length > 0) {
                existing.push(available[Math.floor(Math.random() * available.length)].id);
                disciplinePowers[dName] = existing;
            }
        }
    }

    const specialties = [...selectedPredator.specialties];
    if (selectedPredator.specialtyOptions && selectedPredator.specialtyOptions.length > 0) {
        specialties.push(selectedPredator.specialtyOptions[Math.floor(Math.random() * selectedPredator.specialtyOptions.length)]);
    }

    let advantages = [...selectedPredator.advantages];
    let flaws = [...selectedPredator.flaws];

    // 6. XP Level Adjustments (Simplified for Randomizer)
    let generation = 12;
    let bloodPotency = 1;
    let humanity = 7 + selectedPredator.humanityModifier;

    if (sLevel === 'neonate') { // 15 XP
        generation = Math.floor(Math.random() * (12 - 10 + 1)) + 10; // 10-12
        const bestAttr = priorityAttrs[0];
        attributes[bestAttr] = Math.min(5, attributes[bestAttr] + 1); 
    } else if (sLevel === 'ancilla') { // 35 XP
        generation = Math.floor(Math.random() * (11 - 9 + 1)) + 9; // 9-11
        bloodPotency = 2;
        const bestAttr = priorityAttrs[0];
        attributes[bestAttr] = Math.min(5, attributes[bestAttr] + 1); 
        const bestSkill = prioritySkills[0];
        skills[bestSkill] = Math.min(5, skills[bestSkill] + 1);
        if (clanDiscNames.length > 0) {
            const d1 = clanDiscNames[0];
            disciplines[d1] = Math.min(5, (disciplines[d1] || 0) + 1);
            const details = allDiscDetails[d1];
            if (details) {
                const existing = disciplinePowers[d1] || [];
                const available = details.powers.filter(p => p.level <= disciplines[d1] && !existing.includes(p.id));
                if (available.length > 0) {
                    existing.push(available[Math.floor(Math.random() * available.length)].id);
                    disciplinePowers[d1] = existing;
                }
            }
        }
        advantages.push({ name: fnT('advantages.resources.name'), description: fnT('common.unknown'), cost: 2, type: 'advantage', levels: [2] });
        flaws.push({ name: fnT('flaws.enemy.name'), description: fnT('common.unknown'), cost: 1, type: 'flaw', levels: [1] });
    }

    // Derived Stats
    const health = attributes[Attribute.Stamina] + 3;
    const willpower = attributes[Attribute.Composure] + attributes[Attribute.Resolve];

    return {
        ...oInitialCharacter,
        name: identity.name,
        concept: identity.concept,
        sire: identity.sire,
        clan: selectedClan,
        generation,
        bloodPotency,
        humanity,
        attributes,
        skills,
        disciplines,
        disciplinePowers,
        disciplineCombos: [], // Initialize disciplineCombos for random characters
        predatorType: predatorName,
        specialties,
        advantages,
        flaws,
        health,
        willpower,
        hunger: 1
    };
};

import { GoogleGenAI } from "@google/genai";
import type { Character } from '../types';
import { fnGetClanDetails } from '../constants';

// Always initialize GoogleGenAI with the apiKey from process.env.API_KEY
const oAi = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

type TFunction = (key: string, replacements?: Record<string, string | number>) => string;

function fnBuildBasePrompt(oCharacter: Character, fnT: TFunction, sLocale: string): string {
    const sPromptLanguage = sLocale === 'pt' ? 'Brazilian Portuguese' : 'English';
    const oClanDetails = fnGetClanDetails(fnT);

    const sAdvantagesString = oCharacter.advantages.map(a => `${a.name} (${a.cost})`).join(', ') || fnT('common.noneListed');
    const sFlawsString = oCharacter.flaws.map(f => `${f.name} (${f.cost})`).join(', ') || fnT('common.noneListed');
    const sSpecialtiesString = oCharacter.specialties.map(s => `${fnT(`skills.list.${s.skill}`)} (${s.name})`).join(', ') || fnT('common.noneListed');

    return `
    You are a creative writer for the tabletop role-playing game Vampire: The Masquerade 5th Edition.
    Based on the following character details, generate a compelling response in ${sPromptLanguage}.

    Character Details:
    - ${fnT('characterSheet.name')}: ${oCharacter.name || fnT('common.unnamed')}
    - ${fnT('characterSheet.sire')}: ${oCharacter.sire || fnT('common.unknown')}
    - ${fnT('characterSheet.clan')}: ${oCharacter.clan || fnT('common.unknown')}
    - ${fnT('characterSheet.clanCompulsion')}: ${oCharacter.clan ? oClanDetails[oCharacter.clan].compulsion : fnT('common.unknown')}
    - ${fnT('characterSheet.concept')}: ${oCharacter.concept || fnT('common.notDefined')}
    - ${fnT('characterSheet.ambition')}: ${oCharacter.ambition || fnT('common.notDefined')}
    - ${fnT('characterSheet.desire')}: ${oCharacter.desire || fnT('common.notDefined')}
    - ${fnT('characterSheet.predatorType')}: ${oCharacter.predatorType || fnT('common.notDefined')}
    - ${fnT('characterSheet.advantages')}: ${sAdvantagesString}
    - ${fnT('characterSheet.flaws')}: ${sFlawsString}
    - ${fnT('characterSheet.specialties')}: ${sSpecialtiesString}
    - ${fnT('common.keyAttributes')}: ${Object.entries(oCharacter.attributes).sort((a, b) => b[1] - a[1]).slice(0, 3).map(e => fnT(`attributes.list.${e[0]}`)).join(', ')}
    - ${fnT('common.keySkills')}: ${Object.entries(oCharacter.skills).filter(s => s[1] > 0).sort((a, b) => b[1] - a[1]).slice(0, 3).map(e => fnT(`skills.list.${e[0]}`)).join(', ')}

    ---
    `;
}

// Fix: Updating models to gemini-3-flash-preview as it is the current standard for basic text tasks
export const fnGenerateBackstory = async (oCharacter: Character, fnT: TFunction, sLocale: string): Promise<string> => {
    if (!process.env.API_KEY) return "API key not configured.";
    try {
        const sPrompt = `
        ${fnBuildBasePrompt(oCharacter, fnT, sLocale)}
        ${fnT('gemini.backstoryPrompt')}
        `;
        const oResponse = await oAi.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: sPrompt,
        });
        return oResponse.text;
    } catch (error) {
        console.error("Error generating backstory:", error);
        return fnT('gemini.errorBackstory');
    }
};

