                        <div className="flex space-x-2 mx-2">
                             {[...Array(5)].map((_, nI) => (
                                <div key={nI} className={`w-5 h-5 rounded-sm border border-red-600 ${oCharacter.hunger > nI ? 'bg-red-600' : 'bg-gray-900'}`}></div>
                            ))}
                        </div>
                        <Button variant="secondary" className="px-3 py-1 text-lg font-bold leading-none h-8 w-8 flex items-center justify-center" onClick={() => fnOnUpdateHunger(Math.min(5, oCharacter.hunger + 1))} disabled={oCharacter.hunger >= 5}>+</Button>
                     </div>
                 ) : <p>{oCharacter.hunger}</p>}
