        {sGeneratedContent && <GeminiResult title={sGenerationTitle} content={sGeneratedContent} />}
      </Card>
        {oSelectedDiscipline && (
            <InfoModal title={oSelectedDiscipline.name} onClose={() => fnSetSelectedDiscipline(null)}>
                <div className="space-y-4 text-left">
                    <p className="text-gray-400 italic text-sm">{oSelectedDiscipline.description}</p>
                    {[...oSelectedDiscipline.powers].sort((a,b) => a.level - b.level).map(oPower => (
                        <div key={oPower.id} className="border-t border-gray-700 pt-3">
                            <div className="flex justify-between items-start mb-1">
                                <h4 className="font-bold text-red-400">{fnT('compendium.level')} {oPower.level}: {oPower.name}</h4>
                                <div className="flex items-center text-xs text-gray-400 bg-gray-900 px-2 py-1 rounded border border-gray-700"><BloodIcon /><span>{oPower.cost || "Passive"}</span></div>
                            </div>
                            <p className="text-sm text-gray-300">{oPower.description}</p>
                            <div className="mt-2 p-2 bg-black/30 rounded border-l-2 border-red-900/50 text-xs font-mono text-gray-400"><strong className="text-red-500/80 uppercase tracking-wider mr-1">{fnT('compendium.system')}:</strong>{oPower.system}</div>
                        </div>
                    ))}
                </div>
            </InfoModal>
        )}
    </div>
  );
};

