                        </li>
                    ))}
                </ul>
            ) : <p className="text-gray-400 italic">{fnT('common.noneListed')}</p>}
        </Card>
        <Card className="text-left">
            <h3 className="text-red-500 font-bold text-lg mb-2 border-b border-gray-700 pb-1">{fnT('characterSheet.vitals')}</h3>
            <div className="mb-4 pb-4 border-b border-gray-700">
                 <div className="flex justify-between items-center mb-2">
                    <strong className="text-red-400 text-lg uppercase tracking-widest">{fnT('characterSheet.hunger')}</strong>
                 </div>
                 {fnOnUpdateHunger ? (
                     <div className="flex items-center justify-between bg-black/40 p-4 rounded-lg border border-red-900/30">
                        <Button variant="secondary" className="px-3 py-1 text-lg font-bold leading-none h-10 w-10 flex items-center justify-center hover:bg-red-900/20 transition-colors" onClick={() => fnOnUpdateHunger(Math.max(0, oCharacter.hunger - 1))} disabled={oCharacter.hunger <= 0}>-</Button>
                        <div className="flex space-x-2 mx-4">
                             {[...Array(5)].map((_, nI) => (
                                <button 
                                    key={nI} 
                                    onClick={() => fnOnUpdateHunger(nI + 1)}
                                    className="focus:outline-none transition-transform active:scale-95"
                                >
                                    <BloodIcon 
                                        className={`w-8 h-8 transition-colors duration-300 drop-shadow-[0_0_5px_rgba(220,38,38,0.3)] ${oCharacter.hunger > nI ? 'text-red-600' : 'text-gray-800'}`} 
                                        filled={oCharacter.hunger > nI} 
                                    />
                                </button>
                            ))}
                        </div>
                        <Button variant="secondary" className="px-3 py-1 text-lg font-bold leading-none h-10 w-10 flex items-center justify-center hover:bg-red-900/20 transition-colors" onClick={() => fnOnUpdateHunger(Math.min(5, oCharacter.hunger + 1))} disabled={oCharacter.hunger >= 5}>+</Button>
                     </div>
                 ) : (
                     <div className="flex space-x-2">
                         {[...Array(5)].map((_, nI) => (
                            <BloodIcon 
                                key={nI} 
                                className={`w-8 h-8 ${oCharacter.hunger > nI ? 'text-red-600' : 'text-gray-800'}`} 
                                filled={oCharacter.hunger > nI} 
                            />
                        ))}
                     </div>
                 )}
            </div>
            <div className="space-y-2">
                <div className="flex justify-between items-center">
                    <strong className="text-red-400">{fnT('characterSheet.humanity')}:</strong>
                    <div className="flex items-center">
                        <span className="font-bold text-xl mr-2">{oCharacter.humanity}</span>
                        <div className="flex space-x-1">
                            {[...Array(10)].map((_, nI) => (
                                <div key={nI} className={`w-2 h-4 rounded-sm border border-gray-600 ${oCharacter.humanity > nI ? 'bg-green-600' : 'bg-gray-900'}`}></div>
                            ))}
                        </div>
                    </div>
                </div>
                <div className="flex justify-between items-center">
                    <strong className="text-red-400">{fnT('characterSheet.willpower')}:</strong>
                    <div className="flex items-center">
                         <span className="font-bold text-xl mr-2">{nWillpower}</span>
                         <div className="flex space-x-1">
                            {[...Array(10)].map((_, nI) => (
                                <div key={nI} className={`w-2 h-4 rounded-sm border border-gray-600 ${nWillpower > nI ? 'bg-blue-600 shadow-[0_0_5px_rgba(37,99,235,0.5)]' : 'bg-gray-900 opacity-20'}`}></div>
                            ))}
                        </div>
                    </div>
                </div>
                <div className="flex justify-between items-center">
                    <strong className="text-red-400">{fnT('characterSheet.health')}:</strong>
                    <div className="flex items-center">
                        <span className="font-bold text-xl mr-2">{nHealth}</span>
                        <div className="flex space-x-1">
                            {[...Array(10)].map((_, nI) => (
                                <div key={nI} className={`w-2 h-4 rounded-sm border border-gray-600 ${nHealth > nI ? 'bg-red-800 shadow-[0_0_5px_rgba(153,27,27,0.5)]' : 'bg-gray-900 opacity-20'}`}></div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </Card>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <AdvantageFlawList title={fnT('characterSheet.advantages')} items={oCharacter.advantages} />
        <AdvantageFlawList title={fnT('characterSheet.flaws')} items={oCharacter.flaws} />
      </div>
      <Card className="text-left">
        <h3 className="text-red-500 font-bold text-lg mb-2 border-b border-gray-700 pb-1">{fnT('characterSheet.touchstones')}</h3>
        <p className="text-gray-300 whitespace-pre-wrap">{oCharacter.touchstones || fnT('common.noneListed')}</p>
      </Card>
       <Card className="text-left">
        <h2 className="text-2xl font-bold text-red-400 text-center mb-4">{fnT('characterSheet.gemini.title')}</h2>
        <p className="text-center text-gray-400 mb-6">{fnT('characterSheet.gemini.subtitle')}</p>
        <div className="flex justify-center gap-4 flex-wrap">
          <Button onClick={() => fnHandleGenerate('backstory')} disabled={bIsLoading}>{fnT('characterSheet.gemini.generateBackstory')}</Button>
          <Button onClick={() => fnHandleGenerate('plotHook')} variant="secondary" disabled={bIsLoading}>{fnT('characterSheet.gemini.suggestPlotHooks')}</Button>
          <Button onClick={() => fnHandleGenerate('portrait')} variant="secondary" disabled={bIsLoading}>{fnT('characterSheet.gemini.describePortrait')}</Button>
        </div>
        {bIsLoading && <div className="text-center mt-4">{fnT('gemini.loading')}</div>}
        {sGeneratedContent && <GeminiResult title={sGenerationTitle} content={sGeneratedContent} />}
      </Card>
        {oSelectedDiscipline && (
            <InfoModal title={oSelectedDiscipline.name} onClose={() => fnSetSelectedDiscipline(null)}>
                <div className="space-y-4 text-left">
                    <p className="text-gray-400 italic text-sm">{oSelectedDiscipline.description}</p>
                    {[...oSelectedDiscipline.powers].sort((a,b) => a.level - b.level).map(oPower => (
                        <div key={oPower.id} className="border-t border-gray-700 pt-3">
                            <div className="flex justify-between items-start mb-1">
                                <h4 className="font-bold text-red-400">{fnT('compendium.level')} {oPower.level}: {oPower.name}</h4>
                                <div className="flex items-center text-xs text-gray-400 bg-gray-900 px-2 py-1 rounded border border-gray-700"><BloodIcon className="w-3 h-3 text-red-500 mr-1" /><span>{oPower.cost || "Passive"}</span></div>
                            </div>
                            <p className="text-sm text-gray-300">{oPower.description}</p>
                            <div className="mt-2 p-2 bg-black/30 rounded border-l-2 border-red-900/50 text-xs font-mono text-gray-400"><strong className="text-red-500/80 uppercase tracking-wider mr-1">{fnT('compendium.system')}:</strong>{oPower.system}</div>
                        </div>
                    ))}
                </div>
            </InfoModal>
        )}
    </div>
  );
};

import React, { useState } from 'react';
import type { Character, DisciplineDetail, AdvantageFlaw, Specialty, DisciplineCombo } from '../types';
import { Attribute, Skill } from '../types';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { fnGenerateBackstory, fnGeneratePlotHook, fnGeneratePortraitDescription } from '../services/geminiService';
import { fnGetClanDetails, fnGetDisciplineDetails } from '../constants';
import { useI18n } from '../lib/i18n';
import { InfoIcon } from './InfoIcon';
import { InfoModal } from './InfoModal';


interface CharacterSheetProps {
  character: Character;
  onUpdateHunger?: (hunger: number) => void;
}

type GenerationType = 'backstory' | 'plotHook' | 'portrait';

// Fix: Adding React.FC type to BloodIcon to avoid key prop error in maps
const BloodIcon: React.FC<{ className?: string, filled?: boolean }> = ({ className = "w-3 h-3 text-red-500 mr-1", filled = true }) => (
    <svg 
        xmlns="http://www.w3.org/2000/svg" 
        viewBox="0 0 24 24" 
        fill={filled ? "currentColor" : "none"} 
        stroke="currentColor" 
        strokeWidth={filled ? "0" : "2"}
        className={className}
    >
        <path d="M12 21.35s-7-4.35-7-9.35c0-3.87 3.13-7 7-7s7 3.13 7 7c0 5-7 9.35-7 9.35z" />
        {filled && <path d="M12 21.35c.07.04.028.016.76.76s.723 0 .723 0l.028-.015.071-.041a16.975 16.975 0 001.144-.742 19.58 19.58 0 002.683-2.282c1.944-1.99 3.963-4.98 3.963-8.827a8.25 8.25 0 00-16.5 0c0 3.846 2.02 6.837 3.963 8.827a19.58 19.58 0 002.682 2.282 16.975 16.975 0 001.145.742zM12 13.5a3 3 0 100-6 3 3 0 000 6z" opacity="0.3" />}
    </svg>
);

const AttributeGroup: React.FC<{title: string, attributes: Attribute[], values: Record<Attribute, number>}> = ({title: sTitle, attributes: aAttributes, values: oValues}) => {
    const { t: fnT } = useI18n();
    return (
        <div>
            <h3 className="text-red-500 font-bold text-lg mb-2 border-b border-gray-700 pb-1">{sTitle}</h3>
            <ul>
                {aAttributes.map(sAttr => (
                    <li key={sAttr} className="flex justify-between items-center mb-1">
                        <span>{fnT(`attributes.list.${sAttr}`)}</span>
                        <div className="flex items-center">
                            {[...Array(5)].map((_, nI) => (
                                <div key={nI} className={`w-3 h-3 rounded-full border border-gray-500 ml-1 ${oValues[sAttr] > nI ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                            ))}
                        </div>
                    </li>
                ))}
            </ul>
        </div>
    );
};

const SkillGroup: React.FC<{title: string, skills: Skill[], values: Record<Skill, number>, specialties: Specialty[]}> = ({title: sTitle, skills: aSkills, values: oValues, specialties: aSpecialties}) => {
    const { t: fnT } = useI18n();
    return (
        <div>
            <h3 className="text-red-500 font-bold text-lg mb-2 border-b border-gray-700 pb-1">{sTitle}</h3>
            <ul>
                {aSkills.map(sSkill => {
                    const sSkillSpecialties = aSpecialties.filter(s => s.skill === sSkill).map(s => s.name).join(', ');
                    if (oValues[sSkill] > 0) {
                        return (
                            <li key={sSkill} className="flex justify-between items-center mb-1">
                                <span>{fnT(`skills.list.${sSkill}`)} {sSkillSpecialties && <span className="text-xs text-gray-400">({sSkillSpecialties})</span>}</span>
                                <div className="flex items-center">
                                    {[...Array(5)].map((_, nI) => (
                                        <div key={nI} className={`w-3 h-3 rounded-full border border-gray-500 ml-1 ${oValues[sSkill] > nI ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                                    ))}
                                </div>
                            </li>
                        );
                    }
                    return null;
                })}
            </ul>
        </div>
    );
};

const AdvantageFlawList: React.FC<{ title: string, items: AdvantageFlaw[] }> = ({ title: sTitle, items: aItems }) => {
    const { t: fnT } = useI18n();
    return (
        <Card className="text-left">
            <h3 className="text-red-500 font-bold text-lg mb-2 border-b border-gray-700 pb-1">{sTitle}</h3>
            {aItems.length > 0 ? (
                <ul>
                    {aItems.map((oItem, nIdx) => (
                        <li key={`${oItem.name}-${nIdx}`} className="mb-2">
                            <div className="flex justify-between items-center">
                                <p className="font-bold text-gray-200">{oItem.name}</p>
                                <div className="flex items-center">
                                     {[...Array(5)].map((_, nI) => (
                                        <div 
                                            key={nI} 
                                            className={`w-2 h-2 rounded-full border border-gray-600 ml-1 ${oItem.cost > nI ? 'bg-red-500 border-red-500' : 'bg-transparent opacity-20'}`}
                                        ></div>
                                    ))}
                                </div>
                            </div>
                            <p className="text-sm text-gray-400">{oItem.description}</p>
                        </li>
                    ))}
                </ul>
            ) : <p className="text-gray-400 italic">{fnT('common.noneListed')}</p>}
        </Card>
    );
}

const GeminiResult: React.FC<{title: string, content: string}> = ({title: sTitle, content: sContent}) => (
    <Card className="mt-6 text-left">
        <h3 className="text-xl font-bold text-red-400 mb-3">{sTitle}</h3>
        <p className="text-gray-300 whitespace-pre-wrap">{sContent}</p>
    </Card>
);

export const CharacterSheet: React.FC<CharacterSheetProps> = ({ character: oCharacter, onUpdateHunger: fnOnUpdateHunger }) => {
    const { t: fnT, locale: sLocale } = useI18n();
    const [sGeneratedContent, fnSetGeneratedContent] = useState<string | null>(null);
    const [sGenerationTitle, fnSetGenerationTitle] = useState<string>('');
    const [bIsLoading, fnSetIsLoading] = useState(false);
    const [oSelectedDiscipline, fnSetSelectedDiscipline] = useState<DisciplineDetail | null>(null);

    const oClanDetails = fnGetClanDetails(fnT);
    const oDisciplineDetails = fnGetDisciplineDetails(fnT);

    const fnHandleGenerate = async (sType: GenerationType) => {
        fnSetIsLoading(true);
        fnSetGeneratedContent(null);
        let sContent = '';
        let sTitle = '';
        try {
            switch (sType) {
                case 'backstory':
                    sTitle = fnT('characterSheet.gemini.backstoryTitle');
                    sContent = await fnGenerateBackstory(oCharacter, fnT, sLocale);
                    break;
                case 'plotHook':
                    sTitle = fnT('characterSheet.gemini.plotHookTitle');
                    sContent = await fnGeneratePlotHook(oCharacter, fnT, sLocale);
                    break;
                case 'portrait':
                    sTitle = fnT('characterSheet.gemini.portraitTitle');
                    sContent = await fnGeneratePortraitDescription(oCharacter, fnT, sLocale);
                    break;
            }
        } catch (e) {
            sContent = fnT('gemini.errorGeneric');
        } finally {
            fnSetGeneratedContent(sContent);
            fnSetGenerationTitle(sTitle);
            fnSetIsLoading(false);
        }
    };

    const aPhysicalAttrs = [Attribute.Strength, Attribute.Dexterity, Attribute.Stamina];
    const aSocialAttrs = [Attribute.Charisma, Attribute.Manipulation, Attribute.Composure];
    const aMentalAttrs = [Attribute.Intelligence, Attribute.Wits, Attribute.Resolve];
    const aPhysicalSkills = [Skill.Athletics, Skill.Brawl, Skill.Craft, Skill.Drive, Skill.Firearms, Skill.Larceny, Skill.Melee, Skill.Stealth, Skill.Survival];
    const aSocialSkills = [Skill.AnimalKen, Skill.Etiquette, Skill.Insight, Skill.Intimidation, Skill.Leadership, Skill.Performance, Skill.Persuasion, Skill.Streetwise, Skill.Subterfuge];
    const aMentalSkills = [Skill.Academics, Skill.Awareness, Skill.Finance, Skill.Investigation, Skill.Medicine, Skill.Occult, Skill.Politics, Skill.Science, Skill.Technology];
    const oClanDetail = oCharacter.clan ? oClanDetails[oCharacter.clan] : null;
    const nComposure = oCharacter.attributes[Attribute.Composure] || 0;
    const nResolve = oCharacter.attributes[Attribute.Resolve] || 0;
    const nStamina = oCharacter.attributes[Attribute.Stamina] || 0;
    const nWillpower = nComposure + nResolve;
    const nHealth = nStamina + 3;

    return (
    <div className="space-y-8">
      <Card>
        <div className="flex flex-col md:flex-row gap-6">
            {oCharacter.portraitUrl && (
                 <div className="flex-shrink-0 mx-auto md:mx-0 w-48 h-48 md:w-56 md:h-56">
                    <img src={oCharacter.portraitUrl} alt={oCharacter.name} className="w-full h-full object-cover rounded-lg border-2 border-gray-700 shadow-lg" />
                </div>
            )}
            <div className="flex-grow">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 text-left">
                  <div><strong className="text-red-400">{fnT('characterSheet.name')}:</strong> {oCharacter.name}</div>
                  <div><strong className="text-red-400">{fnT('characterSheet.clan')}:</strong> {oClanDetail?.name || fnT('common.unknown')}</div>
                  <div><strong className="text-red-400">{fnT('characterSheet.sire')}:</strong> {oCharacter.sire}</div>
                  <div className="md:col-span-3"><strong className="text-red-400">{fnT('characterSheet.concept')}:</strong> {oCharacter.concept}</div>
                  <div className="md:col-span-3"><strong className="text-red-400">{fnT('characterSheet.ambition')}:</strong> {oCharacter.ambition}</div>
                  <div className="md:col-span-3"><strong className="text-red-400">{fnT('characterSheet.desire')}:</strong> {oCharacter.desire}</div>
